always @(posedge pclk) begin
    if (~presetn) begin
        control_register <= 8'b0;
        train_history <= 7'b0;
        predict_history <= 8'b0;
        history_full <= 1'b0;
        history_empty <= 1'b1;
        error_flag <= 1'b0;
        interrupt_full <= 1'b0;
        interrupt_error <= 1'b0;
        pslverr <= 4'b0;
    end
end

// APB interface
always @(posedge pclk or posedge presetn) begin
    if (presetn) begin
        // Reset all
    end else begin
        // Read operation
        if (paddr == 10'b0) begin
            prdata <= 8'b0;
        end else begin
            // Not implemented
        end
    end
end

// Write operation
always @(posedge pclk or negedge pready) begin
    if (pwrite) begin
        case (pselx)
            2'b00: control_register <= paddr;
            2'b01: train_history <= paddr;
            2'b10: predict_history <= paddr;
            default: {}
        end;
