always @(posedge pclk or negedge history_shift_valid) begin
    if (history_shift_valid) begin
        predict_history <= train_history + train_taken;
        history_full <= 8'b1;
        if (history_full) interrupt_full <= 1'b1;
        history_empty <= 8'b0;
    end
end

