    if (rotate_left_right) begin
        data_out = data_in << shift_bits_width;
    end else begin
        if (left_right) begin
            data_out = data_in >> shift_bits_width;
        end else begin
            data_out = data_in >> (7 - shift_bits_width);
        end
    end
end

