    initial begin
        for (i = 0; i < NINDEXES; i = i + 1) begin
            for (n = 0; n < NWAYS; n = n + 1) begin
                recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(n);
            end
        end
    end

    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            // Reset counters to initial state
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(n);
                end
            end
        end else begin

            // Hit case
            if (access == 1 && hit == 1) begin
                // Set the accessed way to maximum recency
                recency[index][way_select] <= $clog2(NWAYS) - 1;

                // Decrement other counters
                for (j = 0; j < NWAYS; j = j + 1) begin
                    if (j != index) begin
                        if (recency[j][way_select] > $clog2(NWAYS) - 1) begin
                            recency[j][way_select] <= 1'b0;
                        end
                    end
                end
            end

            // Miss case
            if (access == 1 && hit == 0) begin
                // Find the least recently used way
                reg min_recency, idx;
                integer min_val;
                integer idx_temp;

                initial @(posedge clock);

                for (i = 0; i < NINDEXES; i = i + 1) begin
                    for (n = 0; n < NWAYS; n = n + 1) begin
                        if (recency[i][idx_temp] < min_val) begin
                            min_val = recency[i][idx_temp];
                            idx_temp = i;
                        end
                    end
                end

                min_recency = min_val;

                // Find the index with min_recency
                for (j = 0; j < NWAYS; j = j + 1) begin
                    if (recency[j][idx_temp] == min_recency) begin
                        lru_slot = j;
                        break;
                    end
                end

                // Update recency array for replacement
                recency[lru_slot][way_select] <= $clog2(NWAYS) - 1;

                // Set way_replace to lru_slot
                way_replace = lru_slot;

                // Decrement other counters
                for (k = 0; k < NWAYS; k = k + 1) begin
                    if (k != lru_slot) begin
                        if (recency[k][way_select] > $clog2(NWAYS) - 1) begin
                            recency[k][way_select] <= 1'b0;
                        end
                    end
                end
            end

        end
    end

endmodule

output.rtl/mru_counter_policy.sv:
module mru_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    reg [(NWAYS * $clog2(NWAYS))-1:0] recency [NINDEXES-1:0];

    wire [$clog2(NWAYS)-1:0] mru_slot;

    integer i, n;

    // Initialize recency array to all zeros
    initial begin
        for (i = 0; i < NINDEXES; i = i + 1) begin
            for (n = 0; n < NWAYS; n = n + 1) begin
                recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(n);
            end
        end
    end

    // Handle reset
    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(n);
                end
            end
        end else begin
            if (access) begin
                recency[index][way_select] <= NWAYS - 1;
            end
        end
    end

    // Find the way with the maximum recency value (MRU)
    always_ff @(posedge clock) begin
        if (recency[index][way_select] == NWAYS - 1) begin
            assign mru_slot = way_select;
        end
    end

    assign way_replace = mru_slot;

endmodule

output.rtl/lfu_counter_policy.sv:
module lfu_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32,
    parameter COUNTERW = 2
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    localparam int unsigned MAX_FREQUENCY = $pow(2, COUNTERW) - 1;

    reg [(NWAYS * COUNTERW)-1:0] frequency;

    integer i, n;

    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    frequency[i][(n * COUNTERW) +: COUNTERW] <= COUNTERW'(0);
                end
            end
        end else begin
            if (access) begin
                if (way_select == {1'b0}) begin
                    // Hit: increment frequency
                    frequency[index][(way_select * COUNTERW) +: COUNTERW] <= frequency[index][(way_select * COUNTERW) +: COUNTERW] + 1;
                    if (frequency[index][(way_select * COUNTERW) +: COUNTERW] == MAX_FREQUENCY) begin
                        // Decrement counters of other ways with higher frequency
                        for (n = 0; n < NWAYS; n = n + 1) begin
                            if (frequency[n][(n * COUNTERW) +: COUNTERW] > 2) begin
                                frequency[n][(n * COUNTERW) +: COUNTERW] <= frequency[n][(n * COUNTERW) +: COUNTERW] - 1;
                            end
                        end
                    end
                end
            end else begin
                // Miss: find least frequently used way
                integer min_freq = INFINITY;
                integer best_idx = NWAYS;
                for (n = 0; n < NWAYS; n = n + 1) begin
                    if (frequency[n][0] < min_freq) begin
                        min_freq = frequency[n][0];
                        best_idx = n;
                    end
                end
                way_replace = best_idx;
            end
        end
    end

endmodule

output.rtl/pseudo_lru_tree_policy.sv:
module pseudo_lru_tree_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    localparam int unsigned NBITS_TREE = NWAYS - 1;

    // Recency array to track next way to be replaced
    reg [NBITS_TREE-1:0] recency [NINDEXES-1:0];

    wire [NBITS_TREE-1:0] recency_updated;
    wire [$clog2(NWAYS)-1:0] pseudo_lru_slot;

    integer i;

    // Sequential logic for reset and recency updates
    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i++) begin
                recency[i] <= NBITS_TREE'(0);
            end
        end else begin
            if (access) begin
                recency[index] <= recency_updated;
            end
        end
    end

    // Compute the latest recency update for the current index
    always_comb begin
        recency_updated = recency[index];
    end

    // Select the Pseudo LRU slot
    slot_select_pseudo_lru_tree #(
        .NWAYS (NWAYS)
    ) slot_select_unit (
        .array (recency[index]),
        .index (pseudo_lru_slot)
    );

    assign way_replace = pseudo_lru_slot;

endmodule

module slot_select_pseudo_lru_tree #(
    parameter NWAYS = 4
)(
    input [NWAYS-2:0] array,
    output logic [$clog2(NWAYS)-1:0] index
);

    localparam int unsigned MAX_DEPTH = $clog2(NWAYS);

    integer depth;
    logic [$clog2(NWAYS)-1:0] step;
    logic direction;

    always_comb begin
        depth = $clog2(NWAYS);
        step = $clog2(NWAYS);
        direction = 1;

        for (i = 0; i < NWAYS-1; i++) begin
            if (array[i] == 0) begin
                if (direction == 1) begin
                    index = i;
                    direction = 0;
                end else begin
                    index = i;
                    direction = 1;
                end
                break;
            end
        end

        // If no zero found, keep the last index
        if (index == NWAYS-1) index = NWAYS-2;
    end

endmodule

input.rtl/fifo_policy.sv:
module fifo_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    // FIFO array to track next way to be replaced
    reg [$clog2(NWAYS)-1:0] fifo_array [NINDEXES-1:0];

    integer i;

    // Sequential logic for reset and fifo_array updates
    always_ff @ (posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i++) begin
                fifo_array[i] <= $clog2(NWAYS)'(0);
            end
        end else begin
            if (access) begin
                // Set the fifo_array position for the next replacement
                fifo_array[index] <= fifo_array[index] + $clog2(NWAYS)'(1);
            end
        end
    end

    assign way_replace = fifo_array[index];

endmodule : fifo_policy

