module car_parking_system (
    input wire clk,
    input wire reset,
    input wire vehicle_entry_sensor,
    input wire vehicle_exit_sensor,
    output reg available_spaces,
    output reg count_car,
    output reg led_status,
    output reg [6:0] seven_seg_display_available_tens,
    output reg [6:0] seven_seg_display_available_units,
    output reg [6:0] seven_seg_display_count_tens,
    output reg [6:0] seven_seg_display_count_units
);

reg state; // Idle, Entry, Exit, Full
wire current_available_spaces;
wire current_count_car;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        available_spaces <= 12;
        count_car <= 0;
        led_status <= 1'b1;
        seven_seg_display_available_tens <= "1";
        seven_seg_display_available_units <= "2";
        seven_seg_display_count_tens <= "0";
        seven_seg_display_count_units <= "0";
        state <= Idle;
    end else begin
        case (state)
            Idle: begin
                if (vehicle_entry_sensor) begin
                    available_spaces <= total_spaces - 1;
                    count_car <= count_car + 1;
                    led_status <= 1'b0;
                end
                state <= Entry;
            end
            Entry: begin
                if (vehicle_entry_sensor) begin
                    available_spaces <= available_spaces - 1;
                    count_car <= count_car + 1;
                    led_status <= 1'b1;
                end
                state <= Exit;
            end
            Exit: begin
                if (vehicle_exit_sensor) begin
                    available_spaces <= available_spaces + 1;
                    count_car <= count_car - 1;
                    led_status <= 1'b0;
                end
                state <= Full;
            end
            Full: begin
                if (vehicle_entry_sensor) begin
                    available_spaces <= 12;
                    count_car <= 0;
                    led_status <= 1'b1;
                end
                state <= Idle;
            end
        endcase
    end
end

always @(posedge clk) begin
    if (state == Idle) begin
        current_available_spaces = available_spaces;
        current_count_car = count_car;
    end
    if (state == Entry) begin
        current_available_spaces = available_spaces - 1;
        current_count_car = count_car + 1;
    end
    if (state == Exit) begin
        current_available_spaces = available_spaces + 1;
        current_count_car = count_car - 1;
    end
    if (state == Full) begin
        current_available_spaces = 12;
        current_count_car = 0;
    end
end

assign available_spaces = current_available_spaces;
assign count_car = current_count_car;

always @(posedge clk) begin
    if (led_status) begin
        seven_seg_display_available_tens <= (available_spaces < 8) ? "0" + "{0}" : "1" + "{0}";
        seven_seg_display_available_units <= (available_spaces < 8) ? "0" + "{0}" : "1" + "{0}";
    end else begin
        seven_seg_display_available_tens <= "0";
        seven_seg_display_available_units <= "0";
    end
end

always @(posedge clk) begin
    if (count_car) begin
        seven_seg_display_count_tens <= (count_car < 8) ? "0" + "{0}" : "1" + "{0}";
        seven_seg_display_count_units <= (count_car < 8) ? "0" + "{0}" : "1" + "{0}";
    end else begin
        seven_seg_display_count_tens <= "0";
        seven_seg_display_count_units <= "0";
    end
end

endmodule

input.rtl/car_parking_system.sv:
// This module implements a car parking management system
// - Uses an FSM to handle different states: `IDLE`, `ENTRY_PROCESSING`, `EXIT_PROCESSING`, and `FULL`.

module car_parking_system #(
    parameter TOTAL_SPACES = 12
)(
    input wire clk,
    input wire reset,
    input wire vehicle_entry_sensor,
    input wire vehicle_exit_sensor,
    output reg [$clog2(TOTAL_SPACES)-1:0] available_spaces,
    output reg [$clog2(TOTAL_SPACES)-1:0] count_car,
    output reg led_status,
    output reg [6:0] seven_seg_display_available_tens,
    output reg [6:0] seven_seg_display_available_units,
    output reg [6:0] seven_seg_display_count_tens,
    output reg [6:0] seven_seg_display_count_units
);

    // Local parameters for FSM states
    localparam IDLE            = 2'b00,
               ENTRY_PROCESSING = 2'b01,
               EXIT_PROCESSING  = 2'b10,
               FULL            = 2'b11;

    // Internal signals
    reg [1:0] state, next_state;

    // Seven-segment encoding
    function [6:0] seven_segment_encoding;
        input [3:0] digit;
        begin
            case (digit)
                4'd0: seven_segment_encoding = 7'b1111110; // 0
                4'd1: seven_segment_encoding = 7'b0110000; // 1
                4'd2: seven_segment_encoding = 7'b1101101; // 2
                4'd3: seven_segment_encoding = 7'b1111001; // 3
                4'd4: seven_segment_encoding = 7'b0110011; // 4
                4'd5: seven_segment_encoding = 7'b1011011; // 5
                4'd6: seven_segment_encoding = 7'b1011111; // 6
                4'd7: seven_segment_encoding = 7'b1110000; // 7
                4'd8: seven_segment_encoding = 7'b1111111; // 8
                4'd9: seven_segment_encoding = 7'b1111011; // 9
                default: seven_segment_encoding = 7'b0000000; // Blank display
            endcase
        end
    endfunction

    // Reset logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= IDLE;
        end else begin
            state <= next_state;
        end
    end

    // Next state logic and outputs
    always @(*) begin
        // Defaults
        next_state = state;
        case (state)
            IDLE: begin
                if (vehicle_entry_sensor && available_spaces > 0) begin
                    next_state = ENTRY_PROCESSING;
                end else if (vehicle_exit_sensor && count_car > 0) begin
                    next_state = EXIT_PROCESSING;
                end else if (available_spaces == 0) begin
                    next_state = FULL;
                end
            end
            ENTRY_PROCESSING: begin
                if (available_spaces > 0) begin
                    next_state = IDLE;
                end
            end
            EXIT_PROCESSING: begin
                if (count_car > 0) begin
                    next_state = IDLE;
                end
            end
            FULL: begin
                if (vehicle_exit_sensor) begin
                    next_state = EXIT_PROCESSING;
                end
            end
        endcase
    end

    always@(*)begin
        if(state == FULL) begin
            led_status = 1'b0;
        end else begin
            led_status = 1'b1;
        end
    end

    // Space and count management
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            available_spaces <= TOTAL_SPACES;
            count_car <= 0;
        end else begin
            if (state == ENTRY_PROCESSING) begin
                available_spaces <= available_spaces - 1;
                count_car <= count_car + 1;
            end else if (state == EXIT_PROCESSING) begin
                available_spaces <= available_spaces + 1;
                count_car <= count_car - 1;
            end else begin
                available_spaces <= available_spaces;
                count_car <= count_car;
            end
        end
    end


    // Seven-segment display update
    always @(*) begin
        seven_seg_display_available_tens = seven_segment_encoding(available_spaces / 10);
        seven_seg_display_available_units = seven_segment_encoding(available_spaces % 10);
        seven_seg_display_count_tens = seven_segment_encoding(count_car / 10);
        seven_seg_display_count_units = seven_segment_encoding(count_car % 10);
    end

endmodule

