    input  logic [NS_OP-1:0]     i_operation_sel,
    input  logic                 i_start,
    input  logic [NS_SENSOR-1:0] i_sensor,
    output logic [NS_BEANS-1:0]  o_bean_sel,
    output logic                 o_grind_beans,
    output logic                 o_use_powder,
    output logic                 o_heat_water,
    output logic                 o_pour_coffee,
    output logic                 o_error
);

// Define state types
typedef enum logic [2:0] {
    IDLE     = 3'b000,
    BEAN_SEL = 3'b001,
    GRIND    = 3'b011,
    POWDER   = 3'b111,
    HEAT     = 3'b110,
    POUR     = 3'b100
} state_t;

// Wires/Registers
state_t state_ff, state_nx;
logic [NBW_DLY:0]     counter_ff, counter_nx;
logic [NBW_DLY-1:0]   grind_delay_ff, heat_delay_ff, pour_delay_ff;
logic [NS_OP-1:0]     operation_sel_ff;
logic [NBW_BEANS-1:0] bean_sel_in_ff;
logic                 start_ff;

// Output assignments
always_comb begin : error_logic
    if(state_ff == IDLE) begin
        o_error = (i_sensor[0] | i_sensor[3]) | (&i_operation_sel[2:1]) | (i_operation_sel[1] & i_sensor[1]) | ((i_operation_sel[2] || i_operation_sel[0]) & i_sensor[2]);
    end else begin
        o_error = i_sensor[3];
    end
end

always_ff @(posedge clk) begin : data_regs
    start_ff <= i_start & ~(i_sensor[0] | i_sensor[3]) & (|i_operation_sel[2:1]) & ~(i_operation_sel[1] & i_sensor[1]) & ~((i_operation_sel == 3'b100 || i_operation_sel == 3'b001) & i_sensor[2]);

    if(i_start && state_ff == IDLE) begin
        operation_sel_ff <= i_operation_sel;
        grind_delay_ff   <= i_grind_delay;
        heat_delay_ff    <= i_heat_delay;
        pour_delay_ff    <= i_pour_delay;
        bean_sel_in_ff   <= i_bean_sel;
    end

    counter_ff      <= counter_nx;
end

always_ff @(posedge clk or negedge rst_async_n) begin : reset_regs
    if(~rst_async_n) begin
        state_ff <= IDLE;
    end else begin
        state_ff <= state_nx;
    end
end

always_comb begin
    case(state_ff)
        IDLE: begin
            counter_nx = 0;

            if(start_ff) begin
                if(~(|i_operation_sel[2:1])) begin
                    state_nx = HEAT;
                end else if(i_operation_sel[1]) begin
                    state_nx = BEAN_SEL;
                end else if(i_operation_sel[0]) begin
                    state_nx = POUR;
                end else begin
                    state_nx = POWDER;
                end
            end else begin
                state_nx = IDLE;
            end
        end
        BEAN_SEL: begin
            if(counter_ff >= SEL_CYCLES) begin
                counter_nx = 0;
                state_nx   = GRIND;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = BEAN_SEL;
            end
        end
        GRIND: begin
            if(counter_ff >= grind_delay_ff) begin
                counter_nx = 0;
                if(operation_sel_ff[0]) begin
                    state_nx = POWDER;
                end else begin
                    state_nx = HEAT;
                end
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = GRIND;
            end
        end
        POWDER: begin
            if(counter_ff >= POWDER_CYCLES) begin
                counter_nx = 0;
                state_nx   = POUR;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = POUR;
            end
        end
        HEAT: begin
            if(counter_ff >= heat_delay_ff) begin
                counter_nx = 0;
                if(|operation_sel_ff[1:0]) begin
                    state_nx = POWDER;
                end else begin
                    state_nx = POUR;
                end
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = HEAT;
            end
        end
        POUR: begin
            if(counter_ff >= pour_delay_ff) begin
                counter_nx = 0;
                state_nx   = IDLE;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = POUR;
            end
        end
        default: begin
            counter_nx = 0;
            state_nx   = IDLE;
        end
    endcase
end

// Controller outputs
always_comb begin
    case(state_ff)
        IDLE: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_use_powder    = 1'b0;
            o_grind_beans   = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        BEAN_SEL: begin
            o_bean_sel                      = 1'b0; // Set all bits to 0
            o_bean_sel[bean_sel_in_ff]      = 1'b1; // Only the position of bean_sel_ff should be 1
            o_grind_beans                   = 1'b0;
            o_use_powder                    = 1'b0;
            o_heat_water                    = 1'b0;
            o_pour_coffee                   = 1'b0;
        end
        GRIND: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b1;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        POWDER: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b1;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        HEAT: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b1;
            o_pour_coffee   = 1'b0;
        end
        POUR: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b1;
        end
        default: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
    endcase
end

// End module
endmodule

output.rtl/signed_comparator.sv:
module signed_unsigned_comparator#(
    parameter WIDTH = 5
) (
    input wire [WIDTH-1:0] i_A,
    input wire [WIDTH-1:0] i_B,
    input wire i_enable,
    input wire i_mode,
    output reg o_greater,
    output reg o_less,
    output reg o_equal
);

    localparam bool signed_mode = i_mode == 1;

    always @(*) begin
        if (i_enable) begin
            if (signed_mode) begin
                // Signed comparison logic
                assign o_greater = ((i_A[WIDTH-1] > 0) && (i_B[WIDTH-1] < 0)) ? 1 : ( ((i_A[WIDTH-1] < 0) && (i_B[WIDTH-1] > 0)) ? 1 : 0 );
                assign o_less = ((i_A[WIDTH-1] < 0) && (i_B[WIDTH-1] > 0)) ? 1 : ( ((i_A[WIDTH-1] > 0) && (i_B[WIDTH-1] < 0)) ? 1 : 0 );
                assign o_equal = (i_A == i_B);
            end
            else begin
                // Magnitude mode: unsigned
                assign o_greater = i_A > i_B;
                assign o_less = i_A < i_B;
                assign o_equal = i_A == i_B;
            end
        end else begin
            o_greater = 0;
            o_less = 0;
            o_equal = 0;
        end
    end

endmodule

output.rtl/complex_multiplier.sv:
module complex_multiplier #(
    parameter WIDTH = 32
)(
    input wire clk,
    input wire arst_n,
    input wire a_real, a_imag,
    input wire b_real, b_imag,
    output reg [WIDTH-1:0] result_real,
    output reg [WIDTH-1:0] result_imag
);

    always @(posedge clk or negedge arst_n) begin
        if (!arst_n) begin
            result_real <= 0;
            result_imag <= 0;
        end else begin
            // Compute real part: (a*c) - (b*d)
            result_real = a_real * b_real - a_imag * b_imag;
            // Compute imag part: (a*d) + (b*c)
            result_imag = a_real * b_imag + a_imag * b_real;
        end
    end

endmodule

output.rtl/compression_engine.sv:
module compression_engine (
  input   logic        clk,
  input   logic        reset,
  input   logic [23:0] num_i,
  output  logic [11:0] mantissa_o,
  output  logic [3:0]  exponent_o
);

  logic [23:12] exp_oh;
  logic [3:0] exp_bin;
  logic [3:0] exponent;
  logic [11:0] mantissa;

  // One‑hot encoding of the most significant set bit
  assign exp_oh[23] = num_i[23];
  for (integer i = 0; i < 24; i++) begin
    exp_oh[i] = num_i[i] & ~(num_i[23:i+1]);
  end

  // Convert one‑hot to binary exponent
  onehot_to_bin #(
    .ONE_HOT_W(12),
    .BIN_W(4)
  ) exp_oh_bin (
    .oh_vec_i(exp_oh),
    .bin_vec_o(exp_bin)
  );

  assign exponent = (exp_oh[0]) ? exp_bin + 4'h1 : exp_bin;

  // Extract mantissa based on the exponent
  if (exponent == 0) begin
    mantissa = num_i[11:0];
  else begin
    mantissa = (num_i >> (exp_oh[0] ? 1 : 0)) [12:0];
  end
end

always @(posedge clk or posedge reset) begin
  if (reset) begin
    exponent_o <= 4'd0;
    mantissa_o <= 12'd0;
  end else begin
    exponent_o <= exponent;
    mantissa_o <= mantissa;
  end
end

endmodule

output.rtl/enhanced_fsm_signal_processor.v:
module enhanced_fsm_signal_processor(
    input i_clk,
    input i_rst_n,
    input wire i_enable,
    input wire i_clear,
    input wire i_ack,
    input wire i_fault,
    input wire [4:0] i_vector_1,
    input wire [4:0] i_vector_2,
    input wire [4:0] i_vector_3,
    input wire [4:0] i_vector_4,
    input wire [4:0] i_vector_5,
    input wire [4:0] i_vector_6,
    output reg o_ready,
    output reg o_error,
    output reg [1:0] o_fsm_status,
    output reg [7:0] o_vector_1,
    output reg [7:0] o_vector_2,
    output reg [7:0] o_vector_3,
    output reg [7:0] o_vector_4
);

always_ff @(posedge i_clk) begin
    if (!i_rst_n) begin
        o_ready <= 0;
        o_error <= 0;
        o_fsm_status <= 2'b00;
        o_vector_1 <= 0;
        o_vector_2 <= 0;
        o_vector_3 <= 0;
        o_vector_4 <= 0;
    end else begin
        case (o_fsm_status) is
            2'b00: // IDLE
                if (i_enable) begin
                    o_fsm_status <= 2'b01;
                end else begin
                    o_ready <= 1;
                    o_error <= 0;
                    o_fsm_status <= 2'b00;
                end
        endcase
        case (o_fsm_status) is
            2'b01: // PROCESS
                if (i_clear) begin
                    // Clear outputs and reset fault
                    o_vector_1 <= 0;
                    o_vector_2 <= 0;
                    o_vector_3 <= 0;
                    o_vector_4 <= 0;
                    o_ready <= 1;
                    o_error <= 0;
                    o_fsm_status <= 2'b10;
                end else if (i_ack) begin
                    o_ready <= 1;
                    o_error <= 0;
                    o_fsm_status <= 2'b00;
                end else begin
                    // Stay in PROCESS
                end
        endcase
        case (o_fsm_status) is
            2'b10: // READY
                if (i_ack) begin
                    o_ready <= 1;
                    o_error <= 0;
                    o_fsm_status <= 2'b00;
                end else begin
                    o_ready <= 0;
                    o_error <= 0;
                    o_fsm_status <= 2'b00;
                end
        endcase
        case (o_fsm_status) is
            2'b11: // FAULT
                o_error <= 1;
                o_fsm_status <= 2'b00;
                // No changes
        endcase
    end
end

endmodule

output.rtl/decimator_and_peak_detector.sv:
module advanced_decimator_with_adaptive_peak_detection #(
    parameter N = 8,
    parameter DATA_WIDTH = 16,
    parameter DEC_FACTOR = 4
)(
    input wire clk,
    input wire reset,
    input wire valid_in,
    input data_in[$bits[DATA_WIDTH*N-1:0]],
    output reg valid_out,
    output reg [DATA_WIDTH*N-1:0] data_out,
    output reg [DATA_WIDTH-1:0] peak_value
);

    localparam DEC_FACTOR = 4;

    reg [DATA_WIDTH*N-1:0] data_packed;
    reg [DATA_WIDTH-1:0] decimated_data[0:(N/DEC_FACTOR)-1];
    reg [DATA_WIDTH-1:0] current_peak;

    always @(posedge clk or negedge reset) begin
        if (~reset) begin
            data_packed <= 0;
            decimated_data[0:(N/DEC_FACTOR)-1] <= 0;
            current_peak <= 0;
        end else begin
            for (int i = 0; i < N; i++) begin
                int idx = i * DEC_FACTOR;
                decimated_data[i] <= data_in[idx];
            end
        end
    end

    assign data_packed = {};
    for (int i = 0; i < (N/DEC_FACTOR); i++) begin
        data_packed = data_packed + decimated_data[i];
    end

    assign peak_value = {1, decimated_data[0]};
    for (int i = 1; i < (N/DEC_FACTOR); i++) begin
        current_peak = {current_peak[1], decimated_data[i] > current_peak ? decimated_data[i] : current_peak};
    }

    assign data_out = {};
    for (int i = 0; i < (N/DEC_FACTOR); i++) begin
        data_out = data_out + decimated_data[i];
    end

    assign valid_out = valid_in;

endmodule

output.rtl/sgd_linear_regression.sv:
module sgd_linear_regression #(
    parameter DATA_WIDTH = 16, 
    parameter LEARNING_RATE = 3'd1
) (
    input  logic clk,                               // Clock
    input  logic reset,                             // Asynchronous reset
    input  logic signed [DATA_WIDTH-1:0] x_in,      // Input data (x)
    input  logic signed [DATA_WIDTH-1:0] y_true,    // True output (target)
    output logic signed [DATA_WIDTH-1:0] w,     // Trained weight
    output logic signed [DATA_WIDTH-1:0] b      // Trained bias
);

    localparam NBW_PRED  = 2*DATA_WIDTH + 1;
    localparam NBW_ERROR = NBW_PRED + 1;
    localparam NBW_DELTA = 3 + NBW_ERROR + DATA_WIDTH;

    // Intermediate values
    logic signed [NBW_PRED-1:0] y_pred;  
    logic signed [NBW_ERROR-1:0] error;  
    logic signed [NBW_DELTA-1:0] delta_w; 
    logic signed [NBW_DELTA-1:0] delta_b;

    // Predicted output caculation
    always_comb begin
      y_pred = (w * x_in) + b;
    end

    // Insert the code of Error calculation
    assign error = y_true - y_pred;

    // Insert the code to update the delta_w and delta_b
    assign delta_w = LEARNING_RATE * error * x_in;
    assign delta_b = LEARNING_RATE * error;

    // Insert the code to update the registers w and b
    always_ff @(posedge clk) begin
        if (!reset) begin
            w <= w + delta_w;
            b <= b + delta_b;
        end
    end

endmodule

output.rtl/fsm_linear_reg.sv:
module fsm_linear_reg #(
    parameter DATA_WIDTH = 16
)(
    input  clk,
    input  reset,
    input  start,
    input  x_in,
    input  w_in,
    input  b_in,
    output reg [2*DATA_WIDTH-1:0] result1,
    output reg [DATA_WIDTH:0] result2,
    output reg done
);

    // Internal signals
    localparam IDLE = 2'b00,
        COMPUTE = 2'b01,
        DONE = 2'b10;

    always @(posedge clk or reset) begin
        if (reset) begin
            result1 <= 0;
            result2 <= 0;
            done <= 0;
        end else if (start) begin
            state <= COMPUTE;
        end else begin
            state <= IDLE;
        end
    end

    always @(state) begin
        case (state)
            IDLE: begin
                if (start) begin
                    state <= COMPUTE;
                end
            end
            COMPUTE: begin
                // Weighted sum: w_in * x_in shifted left by 1 (equivalent to multiply by 2)
                result1 <= {[DATA_WIDTH-1:0] w_in*x_in};
                // Bias-adjusted sum: b_in + (x_in >> 2)
                result2 <= b_in + {[DATA_WIDTH-1:0] (x_in >> 2)};
                done <= 1'b1;
            end
            DONE: begin
                done <= 1'b0;
            end
        endcase
    end

endmodule

input.rtl/cont_adder_top.sv:
module continuous_adder (
    input logic         clk,         // Clock signal
    input logic         reset,       // Reset signal, Active high and Synchronous
    input logic [7:0]   data_in,     // Input data stream (8-bit)
    input logic         data_valid,  // Input data valid signal
    output logic [7:0]  sum_out,     // Output the accumulated sum
    output logic        sum_ready    // Signal to indicate sum is output and accumulator is reset
);

    logic [7:0] sum_accum;          // Internal accumulator to store the running sum

    // Sequential logic for sum accumulation
    always_ff @(posedge clk) begin
        if (reset) begin
            // On reset, clear the accumulator, reset sum_out and sum_ready
            sum_accum         <= 8'd0;
            sum_ready         <= 1'b0;
        end
        else begin
            if (data_valid) begin
                // Add input data to the accumulator
                sum_accum     <= sum_accum + data_in;

                // Check if the accumulated sum is >= 100
                if (sum_accum + data_in >= 8'd100) begin
                    // Output the current sum and reset the accumulator
                    sum_out   <= sum_accum + data_in; // Output the accumulated sum
                    sum_ready <= 1'b1;                // Indicate that the sum is ready
                    sum_accum <= 8'd0;                // Reset the accumulator
                end
                else begin
                    // Continue accumulating, but no output until the sum reaches 100
                    sum_ready <= 1'b0;                // No output yet
                end
            end
        end
    end

endmodule

output.rtl/cont_adder_top.sv:
module continuous_adder (
    input logic         clk,
    input logic         reset,
    input logic [DATA_WIDTH-1:0] data_in,
    input logic         data_valid,
    output logic [7:0]  sum_out,
    output logic        sum_ready
);

    logic [DATA_WIDTH-1:0] sum_accum;
    bit signed_flag;

    initial begin
        sum_accum <= 8'd0;
        signed_flag <= signed_input;
    end

    always_ff @(posedge clk) begin
        if (reset) begin
            sum_accum <= 8'd0;
            sum_ready <= 1'b0;
        end else begin
            if (data_valid) begin
                if (signed_flag) begin
                    sum_accum = signed_add(sum_accum, data_in);
                    if (sum_accum >= THRESHOLD_VALUE) begin
                        sum_out = sum_accum + data_in;
                        sum_ready <= 1'b1;
                        sum_accum <= 8'd0;
                    end else if (sum_accum <= -THRESHOLD_VALUE) begin
                        sum_out = sum_accum - data_in;
                        sum_ready <= 1'b1;
                        sum_accum <= 8'd0;
                    end
                end else
                    sum_accum = unsigned_add(sum_accum, data_in);
                    if (sum_accum >= THRESHOLD_VALUE) begin
                        sum_out = sum_accum + data_in;
                        sum_ready <= 1'b1;
                    end else if (sum_accum <= -THRESHOLD_VALUE) begin
                        sum_out = sum_accum - data_in;
                        sum_ready <= 1'b1;
                    end
            end
        end
    end

endmodule

// Helper functions
function bit signed_add(bit signed_flag, bit sum_accum, bit data_in);
    if (signed_flag) begin
        return signed_add_signed(sum_accum, data_in);
    end else
        return signed_add_unsigned(sum_accum, data_in);

function bit signed_add_signed(bit signed_flag, bit sum_accum, bit data_in);
    if (signed_flag) begin
        return sum_accum + data_in;
    end else
        return sum_accum - data_in;

function bit signed_add_unsigned(bit signed_flag, bit sum_accum, bit data_in);
    if (signed_flag) begin
        return sum_accum + data_in;
    end else
        return sum_accum - data_in;

endmodule

input.rtl/cont_adder.sv:
module cont_adder #(
    parameter DATA_WIDTH = 32,
    parameter signed THRESHOLD_VALUE_1 = 50,
    parameter signed THRESHOLD_VALUE_2 = 100,
    parameter SIGNED_INPUTS = 1,
    parameter ACCUM_MODE = 0,
    parameter WEIGHT = 1
) (
    input  logic                         clk,
    input  logic                         reset,
    input  logic signed [DATA_WIDTH-1:0] data_in,
    input  logic                         data_valid,
    input  logic [15:0]                  window_size,
    output logic signed [DATA_WIDTH-1:0] sum_out,
    output logic signed [DATA_WIDTH-1:0] avg_out,
    output logic                         threshold_1,
    output logic                         threshold_2,
    output logic                         sum_ready
);

    // Sequential Registers
    logic signed [DATA_WIDTH+1:0] sum_accum;
    logic [15:0]                  sample_count;

    // Combinational Signals
    logic signed [DATA_WIDTH-1:0] weighted_input;
    logic signed [DATA_WIDTH-1:0] new_sum;
    logic                         threshold_1_comb;
    logic                         threshold_2_comb;
    logic                         sum_ready_reg;

    // Combinational Logic
    always_comb begin
        sum_ready_reg = 0;
        weighted_input = data_in * WEIGHT;
        new_sum = sum_accum + weighted_input;

        threshold_1_comb = (new_sum >= THRESHOLD_VALUE_1) || (new_sum <= -THRESHOLD_VALUE_1);
        threshold_2_comb = (new_sum >= THRESHOLD_VALUE_2) || (new_sum <= -THRESHOLD_VALUE_2);

        if (data_valid) begin
            if (ACCUM_MODE == 0) begin
                if (threshold_1_comb || threshold_2_comb) begin
                    sum_ready_reg = 1;
                end else begin
                    sum_ready_reg = 0;
                end
            end else if (ACCUM_MODE == 1) begin
                if ((sample_count + 1) >= window_size) begin
                    sum_ready_reg = 1;
                end else begin
                    sum_ready_reg = 0;
                end
            end
        end else begin
            sum_ready_reg = 0;
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            sum_accum     <= 0;
            sample_count  <= 0;
            sum_ready     <= 0;
            sum_out       <= 0;
            avg_out       <= 0;
            threshold_1   <= 0;
            threshold_2   <= 0;
        end else if (data_valid) begin
            threshold_1 <= threshold_1_comb;
            threshold_2 <= threshold_2_comb;

            if (ACCUM_MODE == 1) begin  
                sum_accum    <= sum_accum + weighted_input;
                sample_count <= sample_count + 1;
                if (sum_ready_reg) begin
                    sum_out      <= sum_accum + weighted_input;
                    avg_out      <= (sum_accum + weighted_input) / window_size;
                    sum_ready    <= 1;
                    sum_accum    <= 0;
                    sample_count <= 0;
                end else begin
                    sum_ready <= 0;
                    sum_out   <= 0;
                    avg_out   <= 0;
                end
            end else begin  
                sum_accum <= sum_accum + weighted_input;
                if (sum_ready_reg) begin
                    sum_out   <= sum_accum + weighted_input;
                    sum_ready <= 1;
                end else begin
                    sum_ready <= 0;
                    sum_out   <= 0;
                end
                avg_out <= 0; 
            end
        end else begin
            sum_ready <= 0;
        end
    end

endmodule

output.rtl/cont_adder.sv:
module cont_adder #(
    parameter DATA_WIDTH = 32,
    parameter THRESHOLD_VALUE_1 = 50,
    parameter THRESHOLD_VALUE_2 = 100,
    parameter SIGNED_INPUTS = 0,  -- Removed unused parameter
    parameter ACCUM_MODE = 0,
    parameter WEIGHT = 1
) (
    input  logic                         clk,
    input  logic                         reset,
    input  logic signed [DATA_WIDTH-1:0] data_in,
    input  logic                         data_valid,
    input  logic [15:0]                  window_size,
    output logic signed [DATA_WIDTH-1:0] sum_out,
    output logic signed [DATA_WIDTH-1:0] avg_out,
    output logic                         threshold_1,
    output logic                         threshold_2,
    output logic                         sum_ready
);

    // Sequential Registers
    logic signed [DATA_WIDTH+1:0] sum_accum;
    logic [15:0]                  sample_count;

    // Combinational Signals
    logic signed [DATA_WIDTH-1:0] weighted_input;
    logic signed [DATA_WIDTH-1:0] new_sum;
    logic                         threshold_1_comb;
    logic                         threshold_2_comb;
    logic                         sum_ready_reg;

    // Combinational Logic
    always_comb begin
        sum_ready_reg = 0;
        weighted_input = data_in * WEIGHT;
        new_sum = sum_accum + weighted_input;

        threshold_1_comb = (new_sum >= THRESHOLD_VALUE_1) || (new_sum <= -THRESHOLD_VALUE_1);
        threshold_2_comb = (new_sum >= THRESHOLD_VALUE_2) || (new_sum <= -THRESHOLD_VALUE_2);

        if (data_valid) begin
            if (ACCUM_MODE == 0) begin
                if (threshold_1_comb || threshold_2_comb) begin
                    sum_ready_reg = 1;
                end else begin
                    sum_ready_reg = 0;
                end
            end else if (ACCUM_MODE == 1) begin
                if ((sample_count + 1) >= window_size) begin
                    sum_ready_reg = 1;
                end else begin
                    sum_ready_reg = 0;
                end
            end
        end else begin
            sum_ready_reg = 0;
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            sum_accum     <= 0;
            sample_count  <= 0;
            sum_ready     <= 0;
            sum_out       <= 0;
            avg_out       <= 0;
            threshold_1   <= 0;
            threshold_2   <= 0;
        end else if (data_valid) begin
            threshold_1 <= threshold_1_comb;
            threshold_2 <= threshold_2_comb;

            if (ACCUM_MODE == 1) begin  
                sum_accum    <= sum_accum + weighted_input;
                sample_count <= sample_count + 1;
                if (sum_ready_reg) begin
                    sum_out      <= sum_accum + weighted_input;
                    avg_out      <= (sum_accum + weighted_input) / window_size;
                    sum_ready    <= 1;
                    sum_accum    <= 0;
                    sample_count <= 0;
                end else begin
                    sum_ready <= 0;
                    sum_out   <= 0;
                    avg_out   <= 0;
                end
            end else begin  
                sum_accum <= sum_accum + weighted_input;
                if (sum_ready_reg) begin
                    sum_out   <= sum_accum + weighted_input;
                    sum_ready <= 1;
                end else begin
                    sum_ready <= 0;
                    sum_out   <= 0;
                end
                avg_out <= 0; 
            end
        end else begin
            sum_ready <= 0;
        end
    end

endmodule

