                OUTPUT: begin
                    dot_product_out <= acc;
                    dot_product_valid_out <= 1;
                    state <= IDLE;
                end
                default: state <= IDLE;
            endcase
        end
    end

    always @(posedge clk_in) begin
        if (state == OUTPUT) begin
            dot_product_valid_out <= 1; // Valid signal is HIGH in OUTPUT state
        end else begin
            dot_product_valid_out <= 0; // Valid signal is LOW in all other states
        end
