module elevator_control_system (#(
    parameter N = 8,
    parameter DOOR_OPEN_TIME_MS = 500
));

    reg [N-1:0] call_requests_internal;   // Internal copy of call requests
    reg [2:0] present_state, next_state;   // FSM current and next states
    reg [$clog2(N)-1:0] max_request;       // Highest requested floor
    reg [$clog2(N)-1:0] min_request;      // Lowest requested floor

    // Door open time configuration
    `ifdef SIMULATION
        localparam CLK_FREQ_MHZ = 100;
        localparam SIM_DOOR_OPEN_TIME_MS = 0.05;
        localparam DOOR_OPEN_CYCLES = (SIM_DOOR_OPEN_TIME_MS * CLK_FREQ_MHZ * 1000);
`else
        // Real time calculation
        localparam CLK_FREQ_MHZ = 100;
        localparam DOOR_OPEN_CYCLES = (DOOR_OPEN_TIME_MS * CLK_FREQ_MHZ * 1000);
`endif

    reg [$clog2(DOOR_OPEN_CYCLES)-1:0] door_open_counter;

    reg [$clog2(N)-1:0] current_floor_reg, current_floor_next = 0;

    assign current_floor = current_floor_reg;

    // Update overload warning signal
    assign overload_warning = (overload_detected == 1 && present_state == OVERLOAD_HALT);

    // FSM state transition
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            present_state <= IDLE;
            system_status <= IDLE;
            current_floor_reg <= 0;
        end else begin
            next_state = present_state;
            system_status <= next_state;
            current_floor_reg <= current_floor_next;
        end
    end

    // Calculate max_request and min_request
    always @(*) begin
        if (reset) begin
            max_request = 0;
            min_request = {$clog2(N){1'b1}};
        end else begin
            max_request = 0;
            min_request = {$clog2(N){1'b1}};
            for (integer i = 0; i < N; i = i + 1) begin
                if (call_requests_internal[i]) begin
                    if (i > max_request) max_request = i[$clog2(N)-1:0];
                    if (i < min_request) min_request = i[$clog2(N)-1:0];
                end
            end
        end
    end

    always @(posedge clk) begin
        // Reset door open counter when in DOOR_OPEN state
        if (present_state == DOOR_OPEN) begin
            door_open_counter <= DOOR_OPEN_CYCLES;
        end else begin
            door_open_counter <= DOOR_OPEN_CYCLES;
        end
    end

    // Seven-segment display converter
    floor_to_seven_segment floor_display_converter (
        .clk(clk),
        .floor_display({{8-($clog2(N)){1'b0}}}, current_floor_reg),
        .seven_seg_out(seven_seg_out),
        .seven_seg_out_anode(seven_seg_out_anode),
        .thousand(thousand), .hundred(hundred), .ten(ten), .one(one)
    );

endmodule

output.rtl/ethernet_parser.v:
module extract_bytes (
    input wire clk,
    input wire rst,
    input wire vld,
    input wire sof,
    input wire data[31:0],
    input wire eof,
    output wire ack,
    output reg field,
    output reg field_vld
);

// internal signals
reg [3:0] beat_cnt;
reg [4:0] temp_extracted_field;
bit [1:0] state;

initial begin
    beat_cnt <= 0;
    temp_extracted_field <= 0;
    state <= IDLE;
end

always @(posedge clk or negedge rst) begin
    if (!rst) begin
        beat_cnt <= 0;
        temp_extracted_field <= 0;
        state <= IDLE;
        ack <= 1;
        field <= 0;
        field_vld <= 1'b1;
    end else begin
        case (state)
            IDLE: begin
                if (sof && vld) begin
                    state <= EXTRACTING;
                end
                // else wait
            end
            EXTRACTING: begin
                if (beat_cnt == 1) begin
                    temp_extracted_field <= {data[31:16]};
                end
                // else continue
            end
            DONE: begin
                field <= temp_extracted_field;
                field_vld <= 1'b1;
            end
            FAIL_FINAL: begin
                field_vld <= 1'b0;
                state <= IDLE;
            end
        endcase
    end
end

always @(*) begin
    if (ack) begin
        ack = 1;
    end else begin
        ack = 1'b0;
    end
end

endmodule

output.rtl/apb_controller.sv:
module apb_controller (
    input wire clk,
    input wire reset_n,
    input wire select_a_i,
    input wire select_b_i,
    input wire select_c_i,
    input wire addr_a_i [31:0],
    input wire data_a_i [31:0],
    input wire addr_b_i [31:0],
    input wire data_b_i [31:0],
    input wire addr_c_i [31:0],
    input wire data_c_i [31:0],
    output reg apb_psel_o,
    output reg apb_penable_o,
    output reg apb_pwrite_o,
    output reg apb_paddr_o [31:0],
    output wire apb_pready_i
);

reg [3:0] current_event;
reg [3:0] state;
reg [3:0] timeout_counter;

always @(posedge clk) begin
    if (!reset_n) begin
        current_event <= 0;
        state <= 0;
        apb_psel_o <= 1'b0;
        apb_penable_o <= 1'b0;
        apb_pwrite_o <= 1'b0;
        apb_paddr_o <= 0;
        apb_pwdata_o <= 0;
        apb_pready_i <= 1'b0;
        timeout_counter <= 0;
    end else begin
        case (current_event)
            0: begin
                if (select_a_i) begin
                    current_event <= 1;
                end else if (select_b_i) begin
                    current_event <= 2;
                end else if (select_c_i) begin
                    current_event <= 3;
                end else begin
                    current_event <= 0;
                end
            end
            1: begin // Event A
                apb_psel_o = 1'b1;
                apb_pwrite_o = 1'b1;
                apb_paddr_o = addr_a_i;
                apb_pwdata_o = data_a_i;
            end
            2: begin // Event B
                apb_psel_o = 1'b1;
                apb_pwrite_o = 1'b0;
                apb_paddr_o = addr_b_i;
                apb_pwdata_o = data_b_i;
            end
            3: begin // Event C
                apb_psel_o = 1'b1;
                apb_pwrite_o = 1'b0;
                apb_paddr_o = addr_c_i;
                apb_pwdata_o = data_c_i;
            end
        endcase
    end
end

always @(posedge clk) begin
    if (state == 0 && current_event == 0) begin
        apb_penable_o <= 1'b0;
        apb_pwrite_o <= 1'b0;
        apb_paddr_o <= 0;
        apb_pwdata_o <= 0;
    end else if (state == 1 && current_event == 1) begin
        apb_penable_o <= 1'b1;
        apb_pwrite_o <= 1'b0;
        apb_paddr_o <= 0;
    end else if (state == 2 && current_event == 2) begin
        apb_penable_o <= 1'b0;
        apb_pwrite_o <= 1'b0;
    end
end

always @(*) begin
    apb_pready_i <= apb_pwrite_o;
end

always @(posedge clk) begin
    if (apb_pready_i) begin
        timeout_counter <= 0;
    end else begin
        timeout_counter <= timeout_counter + 1;
        if (timeout_counter > 15) begin
            apb_penable_o <= 1'b0;
            apb_pwrite_o <= 1'b0;
            apb_paddr_o <= 0;
            apb_pwdata_o <= 0;
            apb_pready_i <= 1'b0;
        end
    end
end

endmodule

output.rtl/factorial.sv:
module factorial (
    input logic clk,
    input logic arst_n,
    input logic num_in,
    input logic start,
    output logic busy,
    output logic [63:0] fact,
    output logic done
);

    localparam IDLE = 2'b00,
                  BUSY = 2'b01,
                  DONE = 2'b10;

    reg [2:0] state;
    reg [63:0] temp_fact;
    logic done_flag;

    initial begin
        state = IDLE;
    end

    always @(posedge clk) begin
        if (!arst_n) begin
            case (state)
                IDLE: begin
                    if (start) begin
                        state <= BUSY;
                    end
                    // else remain idle
                end
                BUSY: begin
                    temp_fact = 1;
                    for (int i = 1; i <= num_in; i++) begin
                        temp_fact *= i;
                    end
                    fact = temp_fact;
                    done_flag = 1;
                end
                DONE: begin
                    busy = 0;
                    done_flag = 0;
                end
            endcase
        end else begin
            state <= state + 1;
        end
    end

    always @(*) begin
        if (done_flag) begin
            fact = 1; // for safety
            done <= 1;
            done <= 0;
        end
    end

endmodule

output.rtl/fan_controller.sv:
module fan_controller (
    input wire clk,
    input wire reset,
    output reg fan_pwm_out,

    input  wire psel,
    input  wire penable,
    input  wire pwrite,
    input  wire [7:0] paddr,
    input  wire [7:0] pwdata,
    output reg [7:0] prdata,
    output reg pready,
    output reg pslverr
);

reg [7:0] temp_adc_in;
reg [3:0] temp_low, temp_med, temp_high;

always @(posedge clk) begin
  if (reset) begin
    temp_adc_in <= 3'd0;
    temp_low <= 8'h00;
    temp_med <= 8'h08;
    temp_high <= 8'hF0;
  end else begin
    temp_adc_in <= temp_adc_in[7:0];
  end

  temp_low <= 8'h00;
  temp_med <= 8'h08;
  temp_high <= 8'hF0;

  // Now read from temp registers
  temp_adc_in = temp_adc_in[3:0];

  // Determine duty cycle
  if (temp_adc_in <= temp_low) begin
    fan_speed = 25;
  end else if (temp_adc_in <= temp_med) begin
    fan_speed = 50;
  end else if (temp_adc_in <= temp_high) begin
    fan_speed = 75;
  end else begin
    fan_speed = 100;
  end

  // Calculate the number of clock cycles for the PWM
  // Duty cycle percentage: 25% => 64 cycles (half of 128), 50% => 128, 75% => 192, 100% => 255
  // But we can output 1 for full cycle, 0 otherwise.
  if (fan_speed == 25) begin
    fan_pwm_out = 1;
  end else if (fan_speed == 50) begin
    fan_pwm_out = 1;
  end else if (fan_speed == 75) begin
    fan_pwm_out = 1;
  end else if (fan_speed == 100) begin
    fan_pwm_out = 1;
  end else begin
    fan_pwm_out = 0;
  }

  // Output the PWM
  fan_pwm_out <= fan_pwm_out; // Keep it as is.

endalways

endmodule

