module FILO_RTL #(
    parameter DATA_WIDTH = 8,  // Width of the data entries
    parameter FILO_DEPTH = 16  // Depth of the FILO buffer
) (
    input  wire                  clk,       // Clock signal
    input  wire                  reset,     // Asynchronous reset signal
    input  wire                  push,      // Push control signal
    input  wire                  pop,       // Pop control signal
    input  wire [DATA_WIDTH-1:0] data_in,   // Data input
    output reg  [DATA_WIDTH-1:0] data_out,  // Data output
    output reg                   full,      // Full status signal
    output reg                   empty      // Empty status signal
);

  reg [DATA_WIDTH-1:0] memory[FILO_DEPTH-1:0];  
  reg [$clog2(FILO_DEPTH):0] top;  
  reg feedthrough_valid;
  reg [DATA_WIDTH-1:0] feedthrough_data;

  always @(posedge clk or posedge reset) begin
    if (reset) begin
      top <= 0;
      empty <= 1;
      full <= 0;
      feedthrough_valid <= 0;
      data_out <= 0;  
    end else begin

      if (push && pop && empty) begin
        memory[top] <= data_in;
        top <= top + 1;
        feedthrough_valid <= 0;
      end

      if (pop && !empty) begin
        if (feedthrough_valid) begin
          data_out <= feedthrough_data;
          feedthrough_valid <= 0;
        end else begin
          data_out <= memory[top];
          top <= top - 1;
        end
      end

      empty <= (top == 0);
      full  <= (top == FILO_DEPTH);  
    end
  end
endmodule

output.rtl/findfasterclock.sv:
`timescale 1ns/1ps

module FindFasterClock(
    input  wire clk_A,
    input  wire clk_B,
    input  wire rst_n,            // Active-low reset
    output reg  A_faster_than_B,  // 1 if clk_A is measured faster
    output reg  valid             // 1 once both clocks have measured a period
);

    // Internal signals
    reg        measure_B;
    reg [31:0] b_count;
    reg [31:0] periodA;
    reg        done_A;
    reg        measure_A;
    reg [31:0] a_count;
    reg [31:0] periodB;
    reg        done_B;

    // Clock A FSM
    reg [1:0] stateA;  // IDLE, COUNT, DONE
    localparam A_IDLE    = 2'd0,
                   A_COUNT   = 2'd1,
                   A_DONE    = 2'd2;

    // Clock B FSM
    reg [1:0] stateB;  // IDLE, COUNT, DONE
    localparam B_IDLE    = 2'd0,
                   B_COUNT   = 2'd1,
                   B_DONE    = 2'd2;

    // Clock A FSMs
    always @(posedge clk_A or negedge rst_n) begin
        if (!rst_n) begin
            stateA <= A_IDLE;
            measure_B <= 0;
            b_count <= 0;
            periodA <= 0;
            done_A <= 0;
        end else begin
            case (stateA)
                A_IDLE: begin
                    stateA <= A_COUNT;
                end
                A_COUNT: begin
                    if (clk_B) begin
                        b_count <= b_count + 1;
                    end
                    stateA <= A_DONE;
                end
                A_DONE: begin
                    done_A <= 1;
                end
                default: stateA <= A_IDLE;
            endcase
        end
    end

    // Clock B FSM
    always @(posedge clk_B or negedge rst_n) begin
        if (!rst_n) begin
            stateB <= B_IDLE;
            measure_A <= 0;
            a_count <= 0;
            periodB <= 0;
            done_B <= 0;
        end else begin
            case (stateB)
                B_IDLE: begin
                    stateB <= B_COUNT;
                end
                B_COUNT: begin
                    if (clk_A) begin
                        a_count <= a_count + 1;
                    end
                    stateB <= B_DONE;
                end
                B_DONE: begin
                    done_B <= 1;
                end
                default: stateB <= B_IDLE;
            endcase
        end
    end

    // Output logic
    assign A_faster_than_B = (periodB > periodA) ? 1 : 0;
    assign valid = done_A && done_B;

endmodule

