    logic [1:0] controlpath_state;
    logic curr_state;

    // initial states
    always_ff @(posedge clk) begin
        if (rst) begin
            equal   <= 1'b0;
            greater_than <= 1'b0;
            controlpath_state <= S0;
            curr_state <= S0;
