            case (controlpath_state)
                 S0: begin
                     // Initial state: load A and B
                     equal   = 1'b1;
                     greater_than <= 1'b0;
                     controlpath_state <= S1;
                     curr_state <= S1;
                 end
                 S1: begin
                     // computation complete
                     OUT      = A_ff;
                     done     = 1'b1;
                     controlpath_state <= S0;
                     curr_state <= S0;
                 end
                 S2: begin
                     // A_ff > B_ff, subtract
