                    enc_data_out[2*i + 1] = 1'b1;
                end
            end
            enc_valid_out = 1'b1; // Set the valid signal
        end else begin
            enc_valid_out = 1'b0; // Clear the valid signal if no valid input
        end
    end

endmodule

