module moving_average(
    input wire clk,
    input wire reset,
    input  wire [11 : 0] data_in,
    output wire [11 : 0] data_out
);

reg [11 : 0] memory [7 : 0];
reg [14 : 0] sum;
reg [2  : 0] write_address;
wire [2 : 0] next_address;
reg [11 : 0] read_data;

assign next_address=write_address + 1'b1;
assign data_out=sum[14 : 3];

    // write current input to memory
    integer i;
    always @(posedge clk ) begin
        if (reset == 1'b1) begin
            for (i = 0 ;i < 8 ; i = i + 1 ) begin
                memory[i]<='h0;
            end
        end else begin
            memory[write_address]<=data_in;
        end
    end

    // read the oldest element written to memory
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            read_data<='h0;
        end else begin
            read_data<=memory[next_address];
        end
    end

    // increase the write address to move onto the next data
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            write_address<='h0;
        end else begin
            write_address<=write_address + 1'b1;
        end
    end

    // calculate sum by adding the latest data to the sum and substracting the oldest data
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            sum<='h0;
        end else begin
            sum<=sum+data_in-read_data;
        end
    end

endmodule

output.rtl/moving_average.v:
module moving_average(
    input wire clk,
    input wire reset,
    input  wire [11 : 0] data_in,
    output wire [11 : 0] data_out
);

reg [11 : 0] memory [7 : 0];
reg [14 : 0] sum;
reg [2:0] write_address;
wire [2:0] next_address;
reg [11:0] read_data;

parameter wire enable;

always @(posedge clk) begin
    if (enable) begin
        // Write new data to memory
        if (write_address < 8) begin
            memory[write_address] <= data_in;
        end
        write_address <= write_address + 1'b1;

        // Read the oldest data
        if (read_data < 12) begin
            read_data <= memory[next_address];
        end

        // Update the running sum
        sum <= sum + data_in - read_data;

        // Compute the output value
        data_out = sum[14:3];
    end
end

endmodule

