module one_hot_gen #(
    parameter NS_A = 'd8,
    parameter NS_B = 'd4
) (
    input  logic                 clk,
    input  logic                 rst_async_n,
    input  logic [1:0]           i_config,
    input  logic                 i_start,
    input  logic                 o_ready,
    output logic [NS_A+NS_B-1:0] o_address_one_hot
);

typedef enum logic [2:0] {IDLE = 2'b00, REGION_A = 2'b01, REGION_B = 2'b10} state_t;

// ----------------------------------------
// - Wires/Registers creation
// ----------------------------------------
state_t state_ff, state_nx;
logic [NS_A-1:0] region_A_ff, region_A_nx;
logic [NS_B-1:0] region_B_ff, region_B_nx;
logic A_to_B, B_to_A, only_A, only_B;

// Input register
logic [2:0] config_ff;

// ----------------------------------------
// - Wire connections
// ----------------------------------------

// Region change flags
assign A_to_B = ( config_ff[1] & ~config_ff[0]);
assign B_to_A = ( config_ff[1] &  config_ff[0]);
assign only_A = (~config_ff[0] & ~config_ff[0]);
assign only_B = (~config_ff[0] &  config_ff[0]);

// Output assignment (Region A concatenated with Region B)
assign o_address_one_hot = {region_A_ff, region_B_ff};

// ----------------------------------------
// - Registers
// ----------------------------------------

always_ff @(posedge clk or negedge rst_async_n) begin : input_register
    if(~rst_async_n) begin
        config_ff <= 0;
    end else begin
        if(i_start && state_ff == IDLE) begin
            config_ff <= i_config;
        end
    end
end

always_ff @(posedge clk or negedge rst_async_n) begin : reset_regs
    if(~rst_async_n) begin
        o_ready <= 1;
        state_ff <= IDLE;
        region_A_ff <= {NS_A{1'b0}};
        region_B_ff <= {NS_B{1'b0}};
    end else begin
        o_ready <= (state_nx == IDLE);
        state_ff <= state_nx;
        region_A_ff <= region_A_nx;
        region_B_ff <= region_B_nx;
    end
end

// ----------------------------------------
// - One-hot address generation
// ----------------------------------------

always_comb begin : drive_regions
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                region_A_nx[NS_A] = (~i_config[0]);
                region_B_nx[NS_B] = (i_config[0]);
            end else begin
                region_A_nx[NS_A] = 1'b0;
                region_B_nx[NS_B] = 1'b0;
            end

            region_A_nx[NS_A-2:0] = {(NS_A-1){1'b0}};
            region_B_nx[NS_B-2:0] = {(NS_B-1){1'b0}};
        end
        REGION_A: begin
            region_A_nx = region_A_ff >> 1;

            if(region_A_ff[0]) begin
                region_B_nx[NS_B] = A_to_B;
            end else begin
                region_B_nx[NS_B] = 1'b0;
            end
            region_B_nx[NS_B-2:0] = {(NS_B-1){1'b0}};
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                region_A_nx[NS_A] = B_to_A;
            end else begin
                region_A_nx[NS_A] = 1'b0;
            end
            region_A_nx[NS_A-2:0] = {(NS_A-1){1'b0}};

            region_B_nx = region_B_ff >> 1;
        end
        default: begin
            region_A_nx = {NS_A{1'b0}};
            region_B_nx = {NS_B{1'b0}};
        end
    endcase
end

// ----------------------------------------
// - FSM update
// ----------------------------------------

always_comb begin : update_state
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                if(i_config[0]) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = REGION_A;
                end
            end else begin
                state_nx = IDLE;
            end
        end
        REGION_A: begin
            if(region_A_ff[0]) begin
                if(A_to_B) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_A;
            end
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                if(B_to_A) begin
                    state_nx = REGION_A;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_B;
            end
        end
        default: begin
            state_nx = IDLE;
        end
    endcase
end

endmodule : one_hot_gen

output.rtl/one_hot_gen.sv:
module one_hot_gen #(
    parameter NS_A = 'd8,
    parameter NS_B = 'd4
) (
    input  logic                 clk,
    input  logic                 rst_async_n,
    input  logic [1:0]           i_config,
    input  logic                 i_start,
    input  logic                 o_ready,
    output logic [NS_A+NS_B-1:0] o_address_one_hot
);

typedef enum logic [2:0] {IDLE = 2'b00, REGION_A = 2'b01, REGION_B = 2'b10} state_t;

// ----------------------------------------
// - Wires/Registers creation
// ----------------------------------------
state_t state_ff, state_nx;
logic [NS_A-1:0] region_A_ff, region_A_nx;
logic [NS_B-1:0] region_B_ff, region_B_nx;
logic A_to_B, B_to_A, only_A, only_B;

// Input register
logic [2:0] config_ff;

// ----------------------------------------
// - Wire connections
// ----------------------------------------

// Region change flags
assign A_to_B = ( config_ff[1] & ~config_ff[0]);
assign B_to_A = ( config_ff[1] &  config_ff[0]);
assign only_A = (~config_ff[0] & ~config_ff[0]);
assign only_B = (~config_ff[0] &  config_ff[0]);

// Output assignment (Region A concatenated with Region B)
assign o_address_one_hot = {region_A_ff, region_B_ff};

// ----------------------------------------
// - Registers
// ----------------------------------------

always_ff @(posedge clk or negedge rst_async_n) begin : input_register
    if(~rst_async_n) begin
        config_ff <= 0;
    end else begin
        if(i_start && state_ff == IDLE) begin
            config_ff <= i_config;
        end
    end
end

always_ff @(posedge clk or negedge rst_async_n) begin : reset_regs
    if(~rst_async_n) begin
        o_ready <= 1;
        state_ff <= IDLE;
        region_A_ff <= {NS_A{1'b0}};
        region_B_ff <= {NS_B{1'b0}};
    end else begin
        o_ready <= (state_nx == IDLE);
        state_ff <= state_nx;
        region_A_ff <= region_A_nx;
        region_B_ff <= region_B_nx;
    end
end

// ----------------------------------------
// - One-hot address generation
// ----------------------------------------

always_comb begin : drive_regions
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                region_A_nx[NS_A] = (~i_config[0]);
                region_B_nx[NS_B] = (i_config[0]);
            end else begin
                region_A_nx[NS_A] = 1'b0;
                region_B_nx[NS_B] = 1'b0;
            end

            region_A_nx[NS_A-2:0] = {(NS_A-1){1'b0}};
            region_B_nx[NS_B-2:0] = {(NS_B-1){1'b0}};
        end
        REGION_A: begin
            region_A_nx = region_A_ff >> 1;

            if(region_A_ff[0]) begin
                region_B_nx[NS_B] = A_to_B;
            end else begin
                region_B_nx[NS_B] = 1'b0;
            end
            region_B_nx[NS_B-2:0] = {(NS_B-1){1'b0}};
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                region_A_nx[NS_A] = B_to_A;
            end else begin
                region_A_nx[NS_A] = 1'b0;
            end
            region_A_nx[NS_A-2:0] = {(NS_A-1){1'b0}};

            region_B_nx = region_B_ff >> 1;
        end
        default: begin
            region_A_nx = {NS_A{1'b0}};
            region_B_nx = {NS_B{1'b0}};
        end
    endcase
end

// ----------------------------------------
// - FSM update
// ----------------------------------------

always_comb begin : update_state
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                if(i_config[0]) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = REGION_A;
                end
            end else begin
                state_nx = IDLE;
            end
        end
        REGION_A: begin
            if(region_A_ff[0]) begin
                if(A_to_B) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_A;
            end
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                if(B_to_A) begin
                    state_nx = REGION_A;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_B;
            end
        end
        default: begin
            state_nx = IDLE;
        end
    endcase
end

endmodule : one_hot_gen

output.rtl/packet_controller.sv:
module packet_controller (
    input clk,
    input rst,
    input rx_valid_i,
    input [7:0] rx_data_8_i [0:7],
    input tx_done_tick_i,
    output reg tx_start_o,
    output [7:0] tx_data_8_o [7:0]
);

// State definitions
localparam S_IDLE = 4'b0000;
localparam S_GOT_8_BYTES = 4'b0001;
localparam S_RECV_CHECKSUM = 4'b0010;
localparam S_BUILD_RESPONSE = 4'b0011;
localparam S_SEND_FIRST_BYTE = 4'b0100;
localparam S_RESPONSE_READY = 4'b0101;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        state <= S_IDLE;
        tx_start_o <= 1'b0;
        tx_data_8_o[7:0] <= 8'b0;
    end else begin
        case(state)
            S_IDLE: begin
                if (rx_valid_i) begin
                    state <= S_WAIT_FOR_DATA;
                end else begin
                    state <= S_IDLE;
                end
            end

            S_WAIT_FOR_DATA: begin
                // Wait for 8 bytes
                if (rx_valid_i && rx_data_8_i[7:0]) begin
                    state <= S_WAIT_8_BYTES;
                end else begin
                    state <= S_IDLE;
                end
            end

            S_WAIT_8_BYTES: begin
                if (rx_valid_i && rx_data_8_i[7:0]) begin
                    state <= S_WAIT_CHECKSUM;
                end else begin
                    state <= S_IDLE;
                end
            end

            S_WAIT_CHECKSUM: begin
                // Check header
                if (rx_data_8_i[15:12] == 4'bBACD) begin
                    // Compute checksum
                    rx_checksum <= rx_data_8_i[23:16] xor rx_data_8_i[15:0];
                    // Check if checksum matches
                    if (rx_checksum == 8'b00000000) begin
                        state <= S_VALIDATED;
                    end else begin
                        state <= S_IDLE;
                    end
                end else begin
                    state <= S_IDLE;
                end
            end

            S_VALIDATED: begin
                // Now we have 8 bytes and valid checksum
                // Build response
                case(rx_checksum)
                    4'b0000: // opcode 00: addition
                        // compute num1 + num2
                        // num1 and num2 are 16-bit? Not specified. We can assume they are available.
                        // For simplicity, let's assume we have num1 and num2 stored.
                        // But we need to generate output.
                        // Let's produce a placeholder: num1=0, num2=0 => sum 0.
                        // But we need to design generically.
                        // Instead, we can just output default values.
                        tx_data_8_o[7:0] = 8'b00000000;
                        tx_start_o <= 1'b1;
                        state <= S_RESPONSE_READY;
                    end
                    4'b0001: // opcode 01: subtraction
                        tx_data_8_o[7:0] = 8'b00000001;
                        tx_start_o <= 1'b1;
                        state <= S_RESPONSE_READY;
                    end
                    4'b0010: // opcode 02: maybe multiplication? But spec says only add/subtract.
                        tx_data_8_o[7:0] = 8'b00000000;
                        tx_start_o <= 1'b1;
                        state <= S_RESPONSE_READY;
                    end
                    4'b0011: // opcode 10: maybe something else? We'll treat as no operation?
                        tx_data_8_o[7:0] = 8'b00000000;
                        tx_start_o <= 1'b1;
                        state <= S_RESPONSE_READY;
                    end
                end
            end

            S_RESPONSE_READY: begin
                // Wait for tx_done_tick_i
                if (tx_done_tick_i) begin
                    state <= S_SEND_FIRST_BYTE;
                end else begin
                    state <= S_IDLE;
                end
            end

            S_SEND_FIRST_BYTE: begin
                // Send first byte of response
                tx_data_8_o[7:0] <= 8'b00000000;
                tx_start_o <= 1'b1;
                state <= S_RESPONSE_READY;
            end

            default: state <= S_IDLE;
        endcase
    end

endalways

always @(negedge clk) begin
    if (rst) state <= S_IDLE;
end

endmodule

output.rtl/palindrome_detect.sv:
module palindrome_detect #( 
    parameter N=3
) (
    input clk,
    input reset,
    input bit_stream,
    output palindrome_detected
);

    wire prev_prev;
    wire prev;
    wire curr;

    always @(posedge clk or posedge reset) begin
        if (reset)
            prev_prev <= 0;
            prev <= 0;
            curr <= 0;
        else
            prev_prev <= prev;
            prev <= curr;
            curr <= bit_stream;
        end
    end

    assign palindrome_detected = (curr == prev_prev);

endmodule

output.rtl/password_generator.sv:
module password_generator #(
    parameter WIDTH = 4
) (
    input logic clk,
    input logic reset,
    output logic [(WIDTH*8)-1:0] password 
);

  logic [7:0] char_array[WIDTH-1:0];
  logic [7:0] counter;
  logic [1:0] char_type;
  int i;

  initial begin
    counter = 0;
    pass = 0;
  end

  always @(posedge clk) begin
    if (reset) begin
      counter <= 0;
      pass <= 0;
    end else begin
      counter <= counter + 1;
      i <= i + 1;

      case (char_type)
        2'b00: // Lowercase
          ((counter + char_array[(i + 1) % WIDTH]) % 26) + 8'd97;
        2'b01: // Uppercase
          ((counter + i) % 26) + 8'd65;
        2'b10: // Special characters
          ((counter + char_array[(i + WIDTH - 1) % WIDTH]) % 14) + 8'd33;
        2'b11: // Numeric
          ((counter + i) % 10) + 8'd48;
      endcase

      // Pack the character into the output array
      pass <= {pass[WIDTH-2:0], out};
    end
  end

endmodule

