module sdram_controller (
    input wire clk,
    input wire reset,
    input wire [31:0] addr,
    input wire data_in[15:0],
    input wire read, write, sdram_clk,
    input wire sdram_cke, sdram_cs, sdram_ras, sdram_cas, sdram_we, sdram_addr,
    output reg data_out[15:0],
    output reg sdram_clk,
    output reg [31:0] sdram_cke,
    output reg [31:0] sdram_cs,
    output reg [31:0] sdram_ras,
    output reg [31:0] sdram_cas,
    output reg [31:0] sdram_we,
    output reg sdram_addr,
    output reg [31:0] sdram_ba,
    output reg [31:0] sdram_dq,
    output reg dq_out
);

// State machine
reg [3:0] state;
always @(posedge clk) begin
    case(state)
        INIT: begin
            // initialize for 10 clock cycles
            state <= IDLE;
            // do 10 cycles: simple simulation
            #10 state <= IDLE;
            // after 10 cycles, go to IDLE? But maybe we just stay in IDLE?
        end
        IDLE: begin
            // monitor for read/write/refresh
            if (!read && !write && !sdram_refresh) begin
                state <= ACTIVATE;
            end
            if (write) begin
                state <= WRITE;
            end else if (read) begin
                state <= READ;
            end else begin
                state <= IDLE;
            end
        end
        ACTIVATE: begin
            // activate row
            state <= READ;
        end
        READ: begin
            // perform read
            state <= WRITE;
        end
        WRITE: begin
            // perform write
            state <= REFRESH;
        end
        REFRESH: begin
            // refresh rows
            state <= IDLE;
        end
    endcase
end

assign dq_out = sdram_dq;
assign sdram_clk = clk;
assign sdram_cke = sdram_cke;
assign sdram_cs = sdram_cs;
assign sdram_ras = sdram_ras;
assign sdram_cas = sdram_cas;
assign sdram_we = sdram_we;
assign sdram_addr = addr;
assign sdram_ba = ba;
assign sdram_dq = dq;
assign dq_out = dq_out;

endmodule

output.rtl/alu_seq.v:
module alu_seq (
    input i_clk,
    input i_rst_b,
    input [3:0] i_operand_a,
    input [3:0] i_operand_b,
    input [2:0] i_opcode,
    input [7:0] i_key_in,
    output reg [7:0] o_result
);

reg [8:0] p_key = 0xAA;

initial begin
    o_result = 8'b0;
end

always @(i_clk or i_rst_b) begin
    if (i_rst_b)
        o_result <= 8'b0;
    else
    begin
        if (i_key_in == p_key)
        begin
            case (i_opcode)
                2'b00: o_result = i_operand_a + i_operand_b;
                2'b01: o_result = i_operand_a - i_operand_b;
                2'b10: o_result = i_operand_a * i_operand_b;
                2'b11: o_result = i_operand_a & i_operand_b;
                100: o_result = ~i_operand_a;
                101: o_result = ~i_operand_a;
                110: o_result = i_operand_a ^ i_operand_b;
                111: o_result = ~(i_operand_a ^ i_operand_b);
            endcase
        end
        else
        begin
            o_result = 8'b0;
        end
    end
end

endmodule

output.rtl/secure_read_write_bus_interface.v:
module secure_read_write_bus_interface (
    input wire i_addr,
    input wire i_data_in,
    input wire i_key_in,
    input wire i_read_write_enable,
    input wire i_capture_pulse,
    input wire i_reset_bar
);

    localparam p_configurable_key = 8'b10101010; // 0xAA
    localparam p_data_width = 8;
    localparam p_addr_width = 8;

    reg [PADWIDTH-1:0] addr;
    reg [PADWIDTH-1:0] data;
    wire o_error;
    wire o_data_out;

    always @(posedge i_capture_pulse or negedge i_reset_bar) begin
        if (i_reset_bar) begin
            o_error <= 1;
            o_data_out <= 0;
            addr <= 0;
            data <= 0;
        end else begin
            if (i_read_write_enable) begin
                if (i_key_in == p_configurable_key) begin
                    o_data_out = i_data_in;
                    o_error = 0;
                end else begin
                    o_data_out = 0;
                    o_error = 1;
                end
            end else begin
                o_data_out = 0;
                o_error = 0;
            end
        end
    end

endmodule

output.rtl/secure_read_write_register_bank.v:
module secure_read_write_register_bank #(
    parameter p_address_width = 8,
    parameter p_data_width = 8
)(
    input wire [p_addr_width-1:0] i_addr,
    input wire i_data_in,
    input wire i_read_write_enable,
    input wire i_capture_pulse,
    input wire i_rst_n,
    output reg o_data_out
);

reg [31:0] state;
reg is_unlocked;

initial begin
    state = 32'h0;
    is_unlocked = 0;
end

always @(posedge i_capture_pulse or negedge i_rst_n) begin
    if (i_rst_n) begin
        state = 32'd0;
        is_unlocked = 0;
    end else begin
        if (i_rst_n) begin
            state = 32'd0;
        end else begin
            if (i_read_write_enable) begin
                if (state[2:0] == 8'b0 && i_data_in == p_unlock_code_0) begin
                    state[2:0] = 8'b111;
                end else if (state[2:0] == 8'b111 && i_data_in == p_unlock_code_1) begin
                    state[2:0] = 8'b111;
                end
            end else begin
                state = 32'd0;
            end
        end
    end
end

always @(*) begin
    if (~is_unlocked) begin
        o_data_out = 1'b0;
    end else begin
        if (i_addr == 0 && i_data_in == p_unlock_code_0 && state[2:0] == 8'b111) begin
            o_data_out = p_data_width;
        end else if (i_addr == 1 && i_data_in == p_unlock_code_1 && state[2:0] == 8'b111) begin
            o_data_out = p_data_width;
        end else if (i_addr != 0 && i_addr != 1) begin
            o_data_out = 1'b0;
        end else if (i_addr == 0 && i_data_in == 0) begin
            o_data_out = 0;
        end else if (i_addr == 1 && i_data_in == 0) begin
            o_data_out = 0;
        end else if (i_addr == 0 && i_data_in == 0) begin
            o_data_out = 0;
        end else if (i_addr == 1 && i_data_in == 0) begin
            o_data_out = 0;
        end else if (i_addr == 0 && i_data_in == 0) begin
            o_data_out = 0;
        end else if (i_addr == 1 && i_data_in == 0) begin
            o_data_out = 0;
        end
    end
end

endmodule

output.rtl/secure_variable_timer.v:
module secure_variable_timer (
    input wire i_clk,
    input wire i_rst_n,
    input wire i_data_in,
    output reg [3:0] o_time_left,
    output reg o_processing,
    output reg o_completed,
    input wire i_ack
);

    reg [3:0] delay;
    reg [3:0] count;
    reg is_counting;
    reg is_done;
    reg o_processing;
    reg o_completed;

    always @(posedge i_clk) begin
        if (i_rst_n) begin
            o_processing <= 0;
            o_completed <= 0;
            o_time_left <= 15;
            delay <= 0;
            count <= 0;
            is_counting <= 0;
            is_done <= 0;
            state <= Idle;
        end else begin
            state <= case (state)
                Idle: begin
                    if (i_data_in == "1101") begin
                        state <= Configure;
                    end
                end
                Configure: begin
                    if (i_data_in[3:0] == "0110") begin
                        state <= Counting;
                    end
                end
                Counting: begin
                    is_counting <= 1;
                    if (count == (delay[3:0] + 1) * 1000) begin
                        o_completed <= 1;
                        state <= Done;
                    end else begin
                        o_time_left = delay[3:0] + 1;
                        o_time_left = o_time_left - 1;
                        count <= count + 1;
                    end
                end
                Done: begin
                    o_processing <= 0;
                    o_completed <= 1;
                    state <= Idle;
                end
                default: state <= Idle;
            endcase;
        end
    end

endmodule

output.rtl/binary_to_one_hot_decoder_sequential:
module binary_to_one_hot_decoder_sequencial (
    input wire       i_binary_in,
