module signal_correlator(
    input clk,
    input reset,
    input [7:0] input_signal,
    input [7:0] reference_signal,
    output reg [3:0] correlation_output // 4-bit output
);

integer i;
reg [3:0] sum;  

always @(posedge clk or posedge reset) begin
    if (reset) begin
        correlation_output <= 0;
        sum = 0;  
    end else begin
        sum = 0;  
        for (i = 0; i < 8; i = i + 1) begin
            sum = sum + (input_signal[i] & reference_signal[i]); 
        end
    end
end

endmodule

output.rtl/signal_correlator.sv:
module signal_correlator (
    input clk,
    input reset,
    input [7:0] input_signal,
    input [7:0] reference_signal,
    output reg [3:0] correlation_output
);

    integer i;
    reg [3:0] sum;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            correlation_output <= 0;
            sum <= 0;
        end else begin
            sum = 0;
            for (i = 0; i < 8; i = i + 1) begin
                sum = sum + (input_signal[i] & reference_signal[i]);
            end
        end
    end

    correlation_output = sum < 16 ? sum : 15;

endmodule

output.rtl/signedadder.v:
module signedadder #(parameter DATA_WIDTH = 8) (
    input i_clk,
    input i_rst_n,
    input i_start,
    input i_enable,
    input i_mode,
    input i_clear,
    input [DATA_WIDTH-1:0] i_operand_a,
    input [DATA_WIDTH-1:0] i_operand_b,
    output reg [DATA_WIDTH-1:0] o_resultant_sum,
    output reg o_overflow,
    output reg o_ready,
    output reg [1:0] o_status
);

    localparam NUM_STATES = 4;
    reg [NUM_STATES-1:0] current_state;
    reg next_state;

    always @(posedge i_clk or negedge i_rst_n) begin
        if (i_rst_n) begin
            current_state <= 0;
            o_resultant_sum <= 0;
            o_overflow <= 0;
            o_ready <= 1;
            o_status <= 3; // IDLE
            return;
        end else begin
            next_state = current_state;
            case (current_state)
                0: // IDLE
                    if (i_start) begin
                        next_state = 1; // LOAD
                    end else begin
                        next_state = 0;
                    end
                // other states
            endcase
        end
    end

    always_comb begin
        case (current_state)
            1: // LOAD
                // capture inputs
                o_resultant_sum <= i_operand_a;
                o_overflow <= 0;
                o_ready <= 0;
                o_status <= 0;
            // maybe reset inside
        endcase
    end

endmodule

output.rtl/spi_fsm.v:
module spi_fsm (
    input  wire         i_clk,
    input  wire         i_rst_b,
    input  wire [15:0] i_data_in,
    input  wire         i_enable,
    input  wire         i_fault,
    input  wire         i_clear,

    output reg          o_spi_cs_b,
    output reg          o_spi_clk,
    output reg          o_spi_data,
    output reg [4:0]    o_bits_left,
    output reg          o_done,
    output reg [1:0]    o_fsm_state,
);

reg [4:0] bit_counter;

always @(posedge i_clk or negedge i_rst_b) begin
    if (!i_rst_b) begin
        o_spi_cs_b <= 1'b1;
        o_spi_clk <= 1'b0;
        o_spi_data <= 1'b0;
        o_bits_left <= 16'hFFFF;
        o_done <= 1'b0;
        o_fsm_state <= 00;
    end else begin
        if (i_enable) begin
            if (i_clk) begin
                o_spi_cs_b <= 1'b0;
                o_spi_clk <= ~o_spi_clk;
                o_spi_data <= i_data_in[7]; // MSB first
                if (bit_counter > 0) bit_counter <= bit_counter - 1;
                if (bit_counter == 0) o_done <= 1'b1;
            end else begin
                // idle
            end
        end else begin
            o_spi_cs_b <= 1'b1;
            o_spi_clk <= 0;
            o_spi_data <= 1'b0;
        end
    end
end

always @(*) begin
    o_fsm_state = {o_done, o_bits_left};
end

endmodule

output.rtl/unique_number_identifier.v:
module unique_number_identifier #(
    parameter p_bit_width = 8,
    parameter p_max_numbers = 16
)(
    input wire i_clk, 
    input wire i_rst_n, 
    input wire i_ready, 
    input wire [p_bit_width-1:0] i_number, 
    output reg [p_bit_width-1:0] o_unique_number 
);

reg [p_bit_width-1:0] seen[p_bit_width];
reg [3:0] unique_num;
reg [3:0] seen_index;

initial begin
    seen[:] = 0;
    unique_num = 0;
end

always @(posedge i_clk) begin
    if (i_rst_n) begin
        seen[:] = 0;
        unique_num = 0;
    end else begin
        if (i_ready) begin
            if (i_number != 0) begin
                seen_index = i_number;
                seen[seen_index] = 1;
                if (seen[seen_index] == 0)
                    unique_num = i_number;
            end
        end
    end
end

always @(*) begin
    o_unique_number = unique_num;
end

endmodule

input.rtl/sobel_filter.sv:
module sobel_filter (
    input            clk,
    input            rst_n,
    input      [7:0] pixel_in,
    input            valid_in,
    output reg [7:0] edge_out,
    output reg       valid_out
);
    // Internal signals for gradients
    reg signed [10:0] Gx, Gy;  // To accommodate larger values after convolution
    reg [7:0] pixel_buffer[0:8]; // 3x3 pixel window
    integer i;

    // Parameters for thresholding
    parameter THRESHOLD = 11'd128;

    // Sliding window logic
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (i = 0; i < 9; i = i + 1) begin
                pixel_buffer[i] <= 8'd0;
            end    
        end else if (valid_in) begin
            pixel_buffer[8] <= pixel_buffer[7];
            pixel_buffer[7] <= pixel_buffer[6];
            pixel_buffer[6] <= pixel_buffer[5];
            pixel_buffer[5] <= pixel_buffer[4];
            pixel_buffer[4] <= pixel_buffer[3];
            pixel_buffer[3] <= pixel_buffer[2];
            pixel_buffer[2] <= pixel_buffer[1];
            pixel_buffer[1] <= pixel_buffer[0];
            pixel_buffer[0] <= pixel_in;
        end
    end

    // Sobel convolution and edge detection
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            Gx        <= 11'sd0;
            Gy        <= 11'sd0;
            edge_out  <= 8'd0;
            valid_out <= 1'b0;
        end else if (valid_in) begin
            // Compute Gx and Gy using Sobel kernels
            Gx <= -pixel_buffer[6] - (pixel_buffer[3] << 1) - pixel_buffer[0]
                  +pixel_buffer[8] + (pixel_buffer[5] << 1) + pixel_buffer[2];
            Gy <= -pixel_buffer[6] - (pixel_buffer[7] << 1) - pixel_buffer[8]
                  +pixel_buffer[0] + (pixel_buffer[1] << 1) + pixel_buffer[2];

            // Compute gradient magnitude (simplified as |Gx| + |Gy|)
            edge_out <= ((Gx < 0 ? -Gx : Gx) + (Gy < 0 ? -Gy : Gy)) > THRESHOLD ? 8'd255 : 8'd0;

            // Set valid output
