module static_branch_predict (
    input  logic [31:0] fetch_rdata_i,
    input  logic fetch_pc_i,
    input  logic fetch_valid_i,
    output logic predict_branch_taken_o,
    output logic [31:0] predict_branch_pc_o
);

always @(*) begin
    logic signed imm_signed;
    imm_signed = {fetch_rdata_i[31:12]};

    if (imm_signed < 0) begin
        // Predict taken – sign bit indicates branch direction
        predict_branch_taken_o = 1'b1;
        predict_branch_pc_o = fetch_pc_i + imm_signed;
    else
        predict_branch_taken_o = 1'b0;
        predict_branch_pc_o = fetch_pc_i;
    end
end

endmodule

input.rtl/static_branch_predict.sv:
module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o
);
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;


  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  assign imm_jal_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
  assign imm_jalr_type = {{20{instr[31]}}, instr[31:20]}+reg_addr;
  assign imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };

  assign imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7],
    instr[2], instr[11], instr[5:3], 1'b0 };

  assign imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10],
    instr[4:3], 1'b0};

  assign instr_b    = instr[6:0] == OPCODE_BRANCH;
  assign instr_jal  = instr[6:0] == OPCODE_JAL;
  assign instr_jalr = instr[6:0] == OPCODE_JALR;

  assign instr_cb = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b110) | (instr[15:13] == 3'b111));
  assign instr_cj = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b101) | (instr[15:13] == 3'b001));

  always_comb begin
    branch_imm = imm_b_type;

    case(1'b1)
      instr_jal  : branch_imm = imm_jal_type;
      instr_jalr : branch_imm = imm_jalr_type;
      instr_b    : branch_imm = imm_b_type;
      instr_cj   : branch_imm = imm_cj_type;
      instr_cb   : branch_imm = imm_cb_type;
      default    : ;
    endcase
  end
  assign predict_branch_pc_o    = fetch_pc_i + branch_imm; 
  assign instr_b_taken = (instr_b & imm_b_type[31]) | (instr_cb & imm_cb_type[31]);
  assign predict_branch_taken_o = fetch_valid_i & (instr_jal | instr_jalr | instr_cj | instr_b_taken);

endmodule

output.rtl/static_branch_predict.sv:
module static_branch_predict (

    // Input ports
    input  logic [31:0] fetch_rdata_i,
    input  logic [31:0] fetch_pc_i,
    input  logic [31:0] register_addr_i,
    input  logic        fetch_valid_i,

    // Outputs
    output logic        predict_branch_taken_o,
    output logic [31:0] predict_branch_pc_o,
    output logic        predict_confidence_o,
    output logic predict_exception_o,
    output logic [2:0] predict_branch_type_o,
    output logic predict_branch_offset_o
);

    // Internal registers
    logic [31:0] reg_addr;
    logic [31:0] imm_jal_type;
    logic [31:0] imm_jalr_type;
    logic [31:0] imm_b_type;
    logic [31:0] imm_cj_type;
    logic [31:0] imm_cb_type;

    logic [31:0] branch_imm;
  logic [31:0] pred_branch_pc_o;
  logic [2:0] predict_branch_type_o;
  logic predict_branch_offset_o;
  logic predict_confidence_o;
  logic predict_exception_o;

  // --- Branch detection and prediction --------------------------------
  logic [31:0] branch_imm;
  logic [31:0] pred_branch_pc_o;

  always_comb begin
    // Extract branch opcode
    assign pred_branch_pc_o = (fetch_opcode_i == 7'b63) ? fetch_pc_i : 32'h0;

    // Immediate extraction for branch instructions
    assign imm_b_type = {
        {19{fetch_rdata_i[31]}}, fetch_rdata_i[31], fetch_rdata_i[7], fetch_rdata_i[30:25], fetch_rdata_i[11:8], 1'b0
    };

    // Sign‑extend to 32 bits
    assign branch_imm = imm_b_type;

    // Branch type detection
    if (imm_b_type[31] == 1) begin
        predict_branch_taken_o = 1'b1;
        predict_branch_pc_o = fetch_pc_i + branch_imm;
        predict_confidence_o = 8'b00000000;  // Low confidence, not taken
        predict_exception_o = 1'b0;
        predict_branch_type_o = 3'b011;
    end else if (imm_b_type[1:0] == 3'b110) begin
        predict_branch_taken_o = 1'b1;
        predict_branch_pc_o = fetch_pc_i + branch_imm;
        predict_confidence_o = 8'b00000010;  // Backward branch, 90% chance
        predict_exception_o = 1'b0;
        predict_branch_type_o = 3'b001;
    end else if (imm_b_type[1:0] == 3'b101) begin
        predict_branch_taken_o = 1'b1;
        predict_branch_pc_o = fetch_pc_i + branch_imm;
        predict_confidence_o = 8'b00000001;  // Forward branch, 50% chance
        predict_exception_o = 1'b0;
        predict_branch_type_o = 3'b010;
    end else begin
        predict_branch_taken_o = 1'b0;
        predict_branch_pc_o = fetch_pc_i + branch_imm;
        predict_confidence_o = 8'b00000000;  // No branch
        predict_exception_o = 1'b1;
        predict_branch_type_o = 3'b000;
    end

  end

  // --- Confidence, exception, and type --------------------------------
  assign predict_confidence_o = 8'b00000000;  // Default confidence
  assign predict_exception_o = 1'b0;
  assign predict_branch_type_o = 3'b000;
  assign predict_branch_offset_o = branch_imm;

endmodule

module static_branch_predict (
  // Inputs
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Internal signals
  logic [31:0] imm_jal_type,
  logic [31:0] imm_jalr_type,
  logic [31:0] imm_b_type,
  logic [31:0] imm_cj_type,
  logic [31:0] imm_cb_type,
  logic [31:0] branch_imm,
  logic [31:0] instr,
  logic instr_jal,
  logic instr_jalr,
  logic instr_b,
  logic instr_cj,
  logic instr_cb,

  // Outputs
  output logic predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o
);

  logic [31:0] reg_addr;

  // Branch prediction logic
  logic [31:0] imm_jal_type_assign;
  logic [31:0] imm_jalr_type_assign;
  logic [31:0] imm_b_type_assign;
  logic [31:0] imm_cj_type_assign;
  logic [31:0] imm_cb_type_assign;

  assign imm_jal_type = (fetch_rdata_i[6:0] == 8'h6F) ? 32'h0000000000000000 : 0;
  assign imm_jalr_type = (fetch_rdata_i[6:0] == 8'h67) ? 32'h0000000000000000 : 0;
  assign imm_b_type = (fetch_rdata_i[6:0] == 8'h63) ? 32'h0000000000000000 : 0;
  assign imm_cj_type = (fetch_rdata_i[6:0] == 8'h6C) ? 32'h0000000000000000 : 0;
  assign imm_cb_type = (fetch_rdata_i[6:0] == 8'h6B) ? 32'h0000000000000000 : 0;

  // Determine branch type
  assign instr_jal = (instr[6:0] == 8'h6F);
  assign instr_jalr = (instr[6:0] == 8'h67);
  assign instr_b = (instr[6:0] == 8'h63);
  assign instr_cj = (instr[6:0] == 8'h6C);
  assign instr_cb = (instr[6:0] == 8'h6B);

  // Branch taken decision
  assign predict_branch_taken_o = (instr_b) ? (imm_b_type[31] == 1) :
                                        (instr_cj && imm_cj_type[31] > 0) ||
                                        (instr_cb && imm_cb_type[31] > 0);

  // Predicted PC
  assign predict_branch_pc_o = fetch_pc_i + branch_imm;

endmodule

module static_branch_predict(
  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o,

  // Additional outputs
  output logic [7:0]  predict_confidence_o,   // Confidence level in prediction
  output logic        predict_exception_o,    // Exception/misalignment detection
  output logic [2:0]  predict_branch_type_o,  // Type of branch
  output logic [31:0] predict_branch_offset_o // Calculated branch offset
);

  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;
  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;

  // Branch detection and type classification
  if (fetch_valid_i) begin
    if (instr[6:0] == 7'h6F) begin
      // JAL
      imm_jal_type = {12{instr[31]}};
      // Add offset for JAL
    end else if (instr[6:0] == 7'h67) begin
      // JALR
      reg_addr = register_addr_i;
      imm_jalr_type = {{20{instr[31]}}, instr[31:20]} + reg_addr;
      // Add offset for JALR
    end else if (instr[6:0] == 7'h63) begin
      // B-type
      imm_b_type = {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0;
      // Add offset for B-type
    end else if (instr[6:0] == 7'h63) begin
      // CJ or CB (compressed)
      imm_cj_type = {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7], instr[2], instr[11], instr[5:3], 1'b0;
      imm_cb_type = {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10], instr[4:3], 1'b0;
      // Add offset for CJ/CB
    end else begin
      // Default to no branch prediction
    end
  end

  // Compute branch taken flag
  assign predict_branch_taken_o = predict_confidence_o > 50;

  // Compute predicted PC
  assign predict_branch_pc_o = (predict_branch_taken_o) ?
    fetch_pc_i + imm_jal_type  // JAL / JALR
    : fetch_pc_i + imm_b_type  // B-type
    : fetch_pc_i + imm_cj_type; // CJ / CB

  // Confidence level
  assign predict_confidence_o = (fetch_valid_i && !fetch_valid_i) ? 0 : predict_branch_taken_o ? 90 : 50;

  // Exception detection
  assign predict_exception_o = predict_exception_o;

  // Branch type
  assign predict_branch_type_o = (imm_jal_type[31:20] == 3'b0) ? 0 : (imm_b_type[31] == 1'b1) ? 1 : 2;

endmodule

output.rtl/strobe_divider.sv:
module strobe_divider #(
    parameter MaxRatio_g = 10, // Maximum division ratio (positive integer)
    parameter Latency_g  = 1   // Latency: 0 or 1
)(
    input  wire              Clk,        // Clock input
    input  wire              Rst,        // Synchronous reset (active high)
    input  wire [log2ceil(MaxRatio_g)-1:0] In_Ratio,   // Division ratio input
    input  wire              In_Valid,   // Input pulse valid
    output reg             Out_Valid,  // Output pulse valid
    input  wire              Out_Ready   // Output ready signal
);

    // Function to calculate the ceiling of log2
    function integer log2ceil;
        input integer value;
        integer i;
        begin
            log2ceil = 1;
            for (i = 0; (2 ** i) < value; i = i + 1)
                log2ceil = i + 1;
        end
    endfunction

    // Internal state registers
    reg [log2ceil(MaxRatio_g)-1:0] r_Count, r_next_Count; // Counter register
    reg                            r_OutValid, r_next_OutValid; // Registered OutValid signal
    reg                            OutValid_v; // Intermediate OutValid for latency

    // --------------------------------------------------------
    // Combinational Logic
    // --------------------------------------------------------
    always @* begin
        // Hold current state as default
        r_next_Count    = r_Count;
        r_next_OutValid = r_OutValid;

        // Counter logic for division ratio
        // If In_Ratio > 0, increment on each valid input
        if (In_Ratio > 0) begin
            r_Count <= r_Count + 1;
            if (r_Count == In_Ratio) begin
                Out_Valid <= 1;
            end else if (r_Count < In_Ratio) begin
                Out_Valid <= 0;
            end else begin
                Out_Valid <= 0;
            end
        end else begin
            // In_Ratio == 0: output for every valid input pulse
            Out_Valid <= 1;
        end

        // Latency handling
        // For Latency_g = 0: output immediately
        // For Latency_g = 1: delay by one clock cycle
        if (Latency_g == 0) begin
            Out_Valid <= OutValid_v;
        end else begin
            Out_Valid <= OutValid_v;
        end
    end

    // Output ready handshake
    // Maintain Out_Valid until the next clock edge if Out_Ready is deasserted
    // This part is already handled by the assignment.

    // --------------------------------------------------------
    // Sequential Logic
    // --------------------------------------------------------
    always @(posedge Clk) begin
        if (Rst) begin
            // Reset all internal states
            r_Count <= 0;
            r_OutValid <= 0;
            OutValid_v <= 0;
        end else begin
            // Proceed with the above logic
        end
    end

endmodule

input.rtl/swizzler.sv:
module swizzler #(
    // Parameter N: Number of serial data lanes (default is 8)
    parameter int N = 8
)(
    input clk,
    input reset,
    // Serial Input data lanes
    input  logic [N-1:0]                 data_in,
    // Encoded mapping input: concatenation of N mapping indices, each M bits wide
    input  logic [N*$clog2(N)-1:0]       mapping_in,
    // Control signal: 0 - mapping is LSB to MSB, 1 - mapping is MSB to LSB
    input  logic                         config_in,
    // Serial Output data lanes
    output logic [N-1:0]                 data_out
);
    localparam int M = $clog2(N);
    logic [M-1:0] map_idx [N];
    genvar j;
    generate
        for (j = 0; j < N; j++) begin : lane_mapping
            assign map_idx[j] = mapping_in[j*M +: M];
        end
    endgenerate

    always_ff @ (posedge clk) begin
        if (reset) begin
            data_out <= '0;
        end
        else begin
            for (int i = 0; i < N; i++) begin
                if (map_idx[i] >= 0 && map_idx[i] < N) begin
                    if (config_in) begin
                        data_out[i] <= data_in[map_idx[i]];
                    end
                    else begin
                        data_out[N-1-i] <= data_in[map_idx[i]];
                    end
                end
                else begin
                    data_out[i] <= '0;
                end
            end
        end
    end
endmodule

output.rtl/swizzler.sv:
(* Interface: operation_mode *)
(* 3‑bit operation mode: 000, 001, 010, 011, 100, 101, 110, 111 *)
(* 3’b000 → Swizzle Only | 3’b001 → Passthrough | 3’b010 → Reverse | 3’b011 → Swap Halves | 3’b100 → Invert | 3’b101 → Circular Left Shift | 3’b110 → Circular Right Shift | 3’b111 → Default / Same as Swizzle *)

module swizzler #(
    parameter int N = 8
)(
    input clk,
    input reset,
    input  logic [N-1:0] data_in,
    input  logic [N*$clog2(N)-1:0] mapping_in,
    input  logic config_in,
    output logic [N-1:0] data_out
);

    localparam int M = $clog2(N);
    reg [M-1:0] map_idx;
    reg temp_error_flag;
    reg [N-1:0] swizzle_reg;
    reg [N-1:0] operation_reg;
    reg [N-1:0] error_reg;
    reg error_flag;

    (* Interface: operation_mode *)
    interface operation_mode(input [2:0] mode);

    always_ff @(posedge clk) begin
        if (reset) begin
            data_out <= '0;
            error_flag <= 1;
            swizzle_reg <= '0;
            operation_reg <= '0;
            error_reg <= '0;
        end
        else begin
            if (error_flag) begin
                data_out <= '0;
                error_flag <= 0;
                swizzle_reg <= '0;
                operation_reg <= '0;
                error_reg <= '0;
            end

            // Compute mapping indices
            map_idx = mapping_in;
            if (map_idx[i] >= N) begin
                temp_error_flag <= 1;
                data_out <= '0;
                error_flag <= 1;
                swizzle_reg <= '0;
                operation_reg <= '0;
                error_reg <= '0;
            end

            // Swizzle data
            if (config_in)
                data_out[i] <= data_in[map_idx[i]];
            else
                data_out[N-1-i] <= data_in[map_idx[i]];

            // Apply operation mode
            case (operation_mode)
                3'b000: data_out <= swizzle_reg;
                3'b001: data_out <= swizzle_reg;
                3'b010: data_out <= ~swizzle_reg[N-1]; // Invert high bit
                3'b011: data_out <= ~swizzle_reg[0];
                3'b100: data_out <= ~swizzle_reg[M-1];
                3'b101: data_out <= ~swizzle_reg[M-2];
                3'b110: data_out <= ~swizzle_reg[M-1];
                3'b111: data_out <= swizzle_reg;
                default: data_out <= swizzle_reg;
            endcase
        end
    end

endmodule

input.rtl/swizzler.sv:
`timescale 1ns/1ps

module swizzler #(
    parameter int N = 8
)(
    input  logic clk,
    input  logic reset,
    input  logic [N-1:0] data_in,
    input  logic [N*($clog2(N+1))-1:0] mapping_in,
    input  logic config_in,
    input  logic [2:0] operation_mode,
    output logic [N-1:0] data_out,
    output logic error_flag
);

    localparam int M = $clog2(N+1);

    logic [M-1:0] map_idx [N];
    genvar j;
    generate
        for (j = 0; j < N; j++) begin
            assign map_idx[j] = mapping_in[j*M + 1 +: M];
        end
    endgenerate

    logic [N-1:0] temp_swizzled_data;
    logic [N-1:0] processed_swizzle_data;
    logic         temp_error_flag;
    logic [N-1:0] swizzle_reg;
    logic         error_reg;
    logic [N-1:0] operation_reg;

    always_comb begin
        temp_error_flag = 1'b0;

        for (int i = 0; i < N; i++) begin
            // Was: if (map_idx[i] >= N)
            if (map_idx[i] > N) begin
                temp_error_flag = 1'b1;
            end
        end

        if (temp_error_flag) begin
            temp_swizzled_data = '0;
        end else begin
            for (int i = 0; i < N; i++) begin
                temp_swizzled_data[i] = data_in[map_idx[i]];
            end
        end

        for (int i = 0; i < N; i++) begin
            if (config_in) begin
                processed_swizzle_data[i] = temp_swizzled_data[i];
            end else begin
                processed_swizzle_data[i] = temp_swizzled_data[N - 1 - i];
            end
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            swizzle_reg <= '0;
            error_reg   <= 1'b0;
        end else begin
            swizzle_reg <= processed_swizzle_data + 1; 
            error_reg   <= temp_error_flag;
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            operation_reg <= '0;
        end else begin
            case (operation_mode)
                3'b000: operation_reg <= swizzle_reg;
                3'b001: operation_reg <= swizzle_reg;
                3'b010: for (int i = 0; i < N; i++) operation_reg[i] <= swizzle_reg[N-1-i];
                3'b011: operation_reg <= {swizzle_reg[N/2-1:0], swizzle_reg[N-1:N/2]};
                3'b100: operation_reg <= ~swizzle_reg;
                3'b101: operation_reg <= {swizzle_reg[N-2:0], swizzle_reg[N]};
                3'b110: operation_reg <= {swizzle_reg[0], swizzle_reg[N-1:1]};
                default: operation_reg <= swizzle_reg;
            endcase
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out   <= '0;
            error_flag <= 1'b0;
        end else begin
            for (int i = 1; i < N; i++) begin
                data_out[i] <= operation_reg[N-1-i];
            end
            error_flag <= error_reg;
        end
    end

endmodule

output.rtl/swizzler.sv:
`timescale 1ns/1ps

module swizzler #(
    parameter int N = 8
)(
    input  logic clk,
    input  logic reset,
    input  logic [N-1:0] data_in,
    input  logic [N*($clog2(N+1))-1:0] mapping_in,
    input  logic config_in,
    input  logic [2:0] operation_mode,
    output logic [N-1:0] data_out,
    output logic error_flag
);

    localparam int M = $clog2(N+1);

    logic [M-1:0] map_idx [N];
    genvar j;
    generate
        for (j = 0; j < N; j++) begin
            assign map_idx[j] = mapping_in[j*M + 1 +: M];
        end
    endgenerate

    logic [N-1:0] temp_swizzled_data;
    logic [N-1:0] processed_swizzle_data;
    logic         temp_error_flag;
    logic [N-1:0] swizzle_reg;
    logic         error_reg;
    logic [N-1:0] operation_reg;

    always_comb begin
        temp_error_flag = 1'b0;

        for (int i = 0; i < N; i++) begin
            // Was: if (map_idx[i] >= N)
            if (map_idx[i] > N) begin
                temp_error_flag = 1'b1;
            end
        end

        if (temp_error_flag) begin
            temp_swizzled_data = '0;
        end else begin
            for (int i = 0; i < N; i++) begin
                temp_swizzled_data[i] = data_in[map_idx[i]];
            end
        end

        for (int i = 0; i < N; i++) begin
            if (config_in) begin
                processed_swizzle_data[i] = temp_swizzled_data[i];
            end else begin
                processed_swizzle_data[i] = temp_swizzled_data[N - 1 - i];
            end
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            swizzle_reg <= '0;
            error_reg   <= 1'b0;
        end else begin
            swizzle_reg <= processed_swizzle_data + 1; 
            error_reg   <= temp_error_flag;
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            operation_reg <= '0;
        end else begin
            case (operation_mode)
                3'b000: operation_reg <= swizzle_reg;
                3'b001: operation_reg <= swizzle_reg;
                3'b010: for (int i = 0; i < N; i++) operation_reg[i] <= swizzle_reg[N-1-i];
                3'b011: operation_reg <= {swizzle_reg[N/2-1:0], swizzle_reg[N-1:N/2]};
                3'b100: operation_reg <= ~swizzle_reg;
                3'b101: operation_reg <= {swizzle_reg[N-2:0], swizzle_reg[N]};
                3'b110: operation_reg <= {swizzle_reg[0], swizzle_reg[N-1:1]};
                default: operation_reg <= swizzle_reg;
            endcase
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out   <= '0;
            error_flag <= 1'b0;
        end else begin
            for (int i = 1; i < N; i++) begin
                data_out[i] <= operation_reg[N-1-i];
            end
            error_flag <= error_reg;
        end
    end

endmodule

output.rtl/sync_lifo.sv:
module sync_lifo #(
    parameter DATA_WIDTH = 8,
    parameter ADDR_WIDTH = 3
) (
    input wire clock,
    input wire reset,
    input wire write_en,
    input wire read_en,
    input wire data_in,
    output reg empty,
    output reg full,
    output reg [DATA_WIDTH-1:0] data_out
);

    localparam N = ADDR_WIDTH;
    reg [N-1:0] memory [0:N-1];
    int top = 0;

    always @(posedge clock) begin
        if (reset) begin
            memory[0:N-1] = 0;
            top = 0;
            empty = 1'b1;
            full = 1'b0;
        end else begin
            if (write_en) begin
                if (!full) begin
                    memory[top] = data_in;
                    top = (top + 1) mod N;
                end
            end

            if (read_en) begin
                if (empty) begin
                    data_out <= 0;
                    empty = 1'b0;
                    full = 1'b0;
                end else begin
                    data_out <= memory[top];
                    empty = 1'b1;
                    full = 1'b0;
                end
            end
        end
    end

endmodule

`timescale 1ns / 1ps

module sync_lifo #(
    parameter DATA_WIDTH = 8,  // Width of the data
    parameter ADDR_WIDTH = 3   // Number of bits for the address (determines the depth)
)(
    input wire clock,                         // System clock
    input wire reset,                         // Synchronous reset
    input wire write_en,                      // Write enable
    input wire read_en,                       // Read enable
    input wire [DATA_WIDTH-1:0] data_in,      // Data input to be written into LIFO
    output wire empty,                        // Indicates if LIFO is empty
    output wire full,                         // Indicates if LIFO is full
    output wire [DATA_WIDTH-1:0] data_out     // Data output from LIFO
);

    // Calculate depth of the LIFO using the address width
    localparam DEPTH = (1 << ADDR_WIDTH);      // Depth = 2^ADDR_WIDTH

    // Registers for LIFO logic
    reg [DEPTH-1:0] ptr;                       // Pointer for write/read operations
    reg [DEPTH-1:0] lifo_counter;              // Counter to track the number of elements in the LIFO
    reg [DATA_WIDTH-1:0] memory [DEPTH-1:0];   // Memory array to store LIFO data
    reg [DATA_WIDTH-1:0] temp_data_out;        // Temporary register for output data
    integer i;

    // Output assignments for empty and full flags
    assign empty = (lifo_counter == 0) ? 1'b1 : 1'b0;                  // LIFO is empty if counter is zero
    assign full  = (lifo_counter == DEPTH)? 1'b1 : 1'b0;               // LIFO is full if counter equals DEPTH

    // Counters
    always @(posedge clock) begin
        if (reset) begin
            ptr <= {ADDR_WIDTH {1'b0}};                                  // Reset pointer to zero on reset
        end else if (!full && write_en) begin
            memory[ptr] <= data_in;                                      // Write input data into memory at current pointer
            ptr <= ptr + 1;                                              // Increment pointer to next memory location
        end else if (!empty && read_en) begin
            temp_data_out <= memory[ptr - 1'b1];                         // Read data from memory at (pointer - 1)
            ptr <= ptr - 1;                                              // Decrement pointer after reading
        end
    end

    // Error and Valid signals
    assign error = 1'b1;
    assign valid = 1'b0;

    // Output assignments
    assign data_out = temp_data_out;                                     // Assign temp data output to the actual output
    assign empty = (lifo_counter == 0) ? 1'b1 : 1'b0;
    assign full  = (lifo_counter == DEPTH)? 1'b1 : 1'b0;

endmodule

output.rtl/sync_serial_communication_top.sv:
module sync_serial_communication_top (
    input clk,
    input reset_n,
    input data_in [63:0],
    input sel [2:0],
    output reg serial_out,
    output reg done,
    output reg serial_clk
);

    // Internal state variables
    localparam constant integer NUM_BITS = 64;
    localparam constant integer DATA_WIDTH = 8;
    localparam constant integer BITS_PER_BLOCK = 64 / DATA_WIDTH;

    wire [NUM_BITS-1:0] serial_data;
    wire serial_clk;

    always @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            serial_out <= 1'b0;
            done <= 1'b0;
            serial_clk <= 1'b0;
        end else begin
            if (sel == 3'h0) begin
                serial_data <= 0;
                serial_clk <= 1'b0;
            end else if (sel == 3'h1) begin
                serial_data <= data_in[7:0];
                serial_clk <= 1'b1;
            end else if (sel == 3'h2) begin
                serial_data <= data_in[15:8];
                serial_clk <= 1'b1;
            end else if (sel == 3'h3) begin
                serial_data <= data_in[31:16];
                serial_clk <= 1'b1;
            end else if (sel == 3'h4) begin
                serial_data <= data_in[63:32];
                serial_clk <= 1'b1;
            end else begin
                serial_data <= 0;
                serial_clk <= 1'b0;
            end

            serial_out <= serial_data;
            done <= 1'b1;
        end
    end

endmodule

module tx_block (
    input clk,
    input reset_n,
    input data_in,
    input sel,
    output reg serial_out,
    output reg done,
    output reg serial_clk
);

    // Implementation for tx_block
    assign serial_out = data_in[63:0];
    assign done = 1'b1;
    assign serial_clk = 1'b1;

endmodule

module rx_block (
    input clk,
    input reset_n,
    input data_in,
    input sel,
    output reg data_out,
    output reg done,
    output reg serial_clk
);

    // Implementation for rx_block
    assign data_out = serial_data;
    assign done = 1'b1;
    assign serial_clk = 1'b1;

endmodule

module top;
    input clk,
    input reset_n,
    input data_in [63:0],
    input sel [2:0],
    output reg serial_out,
    output reg done,
    output reg serial_clk;

    tx_block tx (
        .clk(clk),
        .reset_n(reset_n),
        .data_in(data_in),
        .sel(sel),
        .serial_out(serial_out),
        .done(done),
        .serial_clk(serial_clk)
    );

    rx_block rx (
        .clk(clk),
        .reset_n(reset_n),
        .data_in(serial_out),
        .sel(sel),
        .data_out(data_out),
        .done(done),
        .serial_clk(serial_clk)
    );

endmodule

