library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;

entity unpack_one_hot is
    generic (
        DST_WIDTH : integer := 512
    );
    port (
        sign           : std_logic;
        size           : std_logic;
        one_hot_selector : std_logic_vector(2 downto 0);
        source_reg     : in std_logic_vector(255 downto 0);
        destination_reg : out std_logic_vector(DST_WIDTH - 1 downto 0)
    );
end entity;

architecture Behavioral of unpack_one_hot is
begin
    -- Convert the source_reg to a vector of appropriate size
    -- We can use a process to iterate over the source_reg in chunks
    -- But we can simplify by using a recursive approach or just assign.

    -- Since we need to iterate over the source_reg in chunks, but maybe we can just copy?
    -- However, the problem says "The unpacking process supports various bit-width selections" so we need to implement the unpacking.

    -- We can create a process that loops over the source_reg and assigns to destination_reg.

    -- But the design requires a loop based on granularity.

    -- We can use a simple assignment: destination_reg <= source_reg; but that's not the case.

    -- Actually, the specification: "The unpacking process supports various bit-width selections based on a one-hot selector input." So we need to implement the different granularity cases.

    -- Let's create a process that iterates over the source_reg in blocks.

    -- For simplicity, we can just set the destination_reg to be the same as source_reg, but with extension if needed.

    -- But we need to handle the different cases.

    -- We'll use a process that uses a state machine or just a direct assignment with conditional statements.

    -- However, the user didn't ask for a full simulation, just the code.

    -- We can use a simple approach: assign the entire source_reg to destination_reg with some shifting if needed.

    -- But the instructions are complex.

    -- Let's try to write a generic VHDL code that uses the one_hot_selector and size to decide how to unpack.

    -- We'll use a sequential process.

    process(clock)
    begin
        if rising_edge(clk) then
            if one_hot_selector(2) = '1' then
                -- size=1: 8-bit segments
                if size = 1 then
                    for i in 0 to source_reg.size-1 step 8 loop
                        -- take 8 bits from source_reg starting at i
                        -- we need to shift and extend.
                        -- destination_reg[i*16+7 downto i*16] = source_reg[i*8 + ...] but it's easier to treat each 8-bit as an 8-bit value.
                        -- Actually, we need to convert each 8-bit segment to an 8-bit value, sign-extended or zero-extended.
                        -- But the output is 512 bits, so we just copy.
                        destination_reg(i*16*8 + 7 downto i*16*8) <= source_reg(i*8 + 7 downto i*8);
                    end loop;
                elsif size = 0 then
                    for i in 0 to source_reg.size-1 step 4 loop
                        destination_reg(i*8*8 + 7 downto i*8*8) <= source_reg(i*4 + 7 downto i*4);
                    end loop;
                else
                    -- default: copy directly
                    destination_reg <= source_reg;
                end if;
            elsif one_hot_selector(2) = '0' then
                -- size=0, 4-bit segments
                for i in 0 to source_reg.size-1 step 4 loop
                    destination_reg(i*8*4 + 7 downto i*8*4) <= source_reg(i*4 + 7 downto i*4);
                end loop;
            else
                -- size=1, 2-bit segments
                for i in 0 to source_reg.size-1 step 2 loop
                    destination_reg(i*8*2 + 7 downto i*8*2) <= source_reg(i*2 + 7 downto i*2);
                end loop;
            end if;
        end if;
    end process;
end architecture;

output.rtl/vending_machine.sv:
`timescale 1ns / 1ps

interface vending_machine_if;
    input clk;
    input rst;
    input item_button;
    input [2:0] item_selected;
    input [3:0] coin_input;
    input cancel;

    output reg dispense_item;
    output reg return_change;
    output reg [4:0] item_price;
    output reg [4:0] change_amount;
    output reg [2:0] dispense_item_id;
    output reg error;
    output reg return_money;
endinterface

module vending_machine (input clk, input rst, input item_button, input [2:0] item_selected, input [3:0] coin_input, input cancel);
    localparam itidle = 1'b0;
    localparam ititem_select = 1'b1;
    localparam itpayment = 1'b2;
    localparam itdispense = 1'b3;
    localparam itreturn_change = 1'b4;
    localparam itreturntm = 1'b5;
    localparam itidle_after_canc = 1'b6;

    reg [4:0] item_price_reg;
    reg change_amount_reg;
    reg dispense_item_id_reg;
    reg error_flag;
    reg return_money_flag;
    reg dispense_item_done;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            item_price_reg <= 5'd0;
            change_amount_reg <= 5'd0;
            dispense_item_id_reg <= 3'b000;
            error_flag <= 0;
            return_money_flag <= 0;
            dispense_item_done <= 0;
        end else begin
            case (item_select)
                itidle: begin
                    if (item_button) begin
                        item_select <= ititem_select;
                    end
                end
                ititem_select: begin
                    if (item_selected[0] == 1'b0) begin
                        item_select <= itidle;
                    end
                end
                itpayment: begin
                    if (coin_input[0] != 1'b0 && coin_input[0] != 1'b1 && coin_input[0] != 1'b2 && coin_input[0] != 1'b5 && coin_input[0] != 1'b10) begin
                        error_flag <= 1;
                        return_money_flag <= 1;
                        item_price_reg <= 5'd0;
                        change_amount_reg <= 5'd0;
                        dispense_item_id_reg <= 3'b000;
                        dispense_item_done <= 0;
                    end else begin
                        coin_accumulated <= coin_accumulated + coin_input[0];
                    end
                end
                itdispense: begin
                    if (coin_accumulated >= item_price_reg) begin
                        dispense_item_done <= 1;
                        dispense_item_id_reg <= 3'b001;
                        item_price_reg <= 5'd0;
                        change_amount_reg <= 5'd0;
                        return_money_flag <= 0;
                    end else begin
                        error_flag <= 1;
                        return_money_flag <= 1;
                        dispense_item_done <= 0;
                    end
                end
                itreturn_change: begin
                    if (coin_accumulated > item_price_reg) begin
                        change_amount_reg <= coin_accumulated - item_price_reg;
                        dispense_item_done <= 1;
                        item_price_reg <= 5'd0;
                    end else begin
                        return_money_flag <= 0;
                    end
                end
                itreturntm: begin
                    if (return_money_flag) begin
                        return_money_flag <= 0;
                        dispense_item_done <= 1;
                        item_price_reg <= 5'd0;
                    end
                end
                itidle_after_canc: begin
                    error_flag <= 1;
                    return_money_flag <= 1;
                    dispense_item_done <= 0;
                end
            endcase
        end
    end
endmodule

output.rtl/vga_controller.sv:
module vga_controller (
    input wire clk,
    input wire reset,
    input wire color_in[7:0],
    output reg hsync,
    output reg vsync,
    output reg red, green, blue,
    output reg next_x, next_y,
    output reg sync,
    output reg blank
);

reg hcounter, vcounter, h_front, v_front, h_back, v_back;
reg state;

initial begin
    hsync = vsync = red = green = blue = next_x = next_y = sync = blank = '0;
end

always_ff @(posedge clk) begin
    if (reset) begin
        hcounter <= 0;
        vcounter <= 0;
        sync <= '0;
        blank <= '0;
        red = 0; green = 0; blue = 0;
        hsync = vsync = '0;
    end else begin
        if (h_active) begin
            hcntr <= hcntr + 1;
            if (hcntr == 640) begin
                hcntr <= 0;
                hsync <= '1;
                vsync <= '0;
                red <= color_in[7:5];
                green <= color_in[4:2];
                blue <= color_in[1:0];
            end
        end else if (h_front) begin
            h_front <= 0;
        end else if (h_back) begin
            h_back <= 0;
        end else begin
            sync <= '0;
        end
    end
end

endmodule

module vga_controller (
    input logic clock,
    input logic reset,
    input logic [7:0] color_in,
    output logic [9:0] next_x,
    output logic [9:0] next_y,
    output logic hsync,
    output logic vsync,
    output logic [7:0] red,
    output logic [7:0] green,
    output logic [7:0] blue,
    output logic sync,
    output logic clk,
    output logic blank,
    output logic [7:0] h_state,
    output logic [7:0] v_state,
);

    parameter logic [9:0] H_ACTIVE  = 10'd640;
    parameter logic [9:0] H_FRONT   = 10'd16;
    parameter logic [9:0] H_PULSE   = 10'd96;
    parameter logic [9:0] H_BACK    = 10'd48;
    parameter logic [9:0] V_ACTIVE  = 10'd480;
    parameter logic [9:0] V_FRONT   = 10'd10;
    parameter logic [9:0] V_PULSE   = 10'd2;
    parameter logic [9:0] V_BACK    = 10'd33;
    parameter logic LOW   = 1'b0;
    parameter logic HIGH  = 1'b1;
    parameter logic [7:0] H_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] H_FRONT_STATE   = 8'd1;
    parameter logic [7:0] H_PULSE_STATE   = 8'd2;
    parameter logic [7:0] H_BACK_STATE    = 8'd3;
    parameter logic [7:0] V_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] V_FRONT_STATE   = 8'd1;
    parameter logic [7:0] V_PULSE_STATE   = 8'd2;
    parameter logic [7:0] V_BACK_STATE    = 8'd3;

    logic line_done;
    logic [9:0] h_counter;
    logic [9:0] v_counter;

    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            h_counter   <= 10'd0;
            v_counter   <= 10'd0;
            h_state     <= H_ACTIVE_STATE;
            v_state     <= V_ACTIVE_STATE;
            line_done   <= LOW;
        end else begin
            case (h_state)
                H_ACTIVE_STATE: begin
                    if (h_counter < H_ACTIVE_STATE - 1) begin
                        h_counter <= h_counter + 1;
                    end else begin
                        h_state <= H_FRONT_STATE;
                    end
                end
                H_FRONT_STATE: begin
                    if (h_counter < H_FRONT - 1) begin
                        h_counter <= h_counter + 1;
                    end else begin
                        h_state <= H_PULSE_STATE;
                    end
                end
                H_PULSE_STATE: begin
                    hsync <= LOW;
                    if (h_counter < H_PULSE_STATE - 1) begin
                        h_counter <= h_counter + 1;
                    end else begin
                        h_state <= H_BACK_STATE;
                    end
                end
                H_BACK_STATE: begin
                    h_state <= H_ACTIVE_STATE;
                    hsync <= HIGH;
                    h_counter <= 10'd0;
                end
            endcase

            case (v_state)
                V_ACTIVE_STATE: begin
                    if (v_counter < V_ACTIVE - 1) begin
                        v_counter <= v_counter + 1;
                    end else begin
                        v_state <= V_FRONT_STATE;
                    end
                end
                V_FRONT_STATE: begin
                    if (v_counter < V_FRONT - 1) begin
                        v_counter <= v_counter + 1;
                    end else begin
                        v_state <= V_PULSE_STATE;
                    end
                end
                V_PULSE_STATE: begin
                    vsync <= LOW;
                    if (v_counter < V_PULSE_STATE - 1) begin
                        v_counter <= v_counter + 1;
                    end else begin
                        v_state <= V_BACK_STATE;
                    end
                end
                V_BACK_STATE: begin
                    v_state <= V_ACTIVE_STATE;
                    vsync <= HIGH;
                    v_counter <= 10'd0;
                end
            endcase

            // RGB handling
            if (h_state == H_ACTIVE_STATE) begin
                red   <= color_in[0];
                green <= color_in[1];
                blue  <= color_in[2];
            end else begin
                red   <= 0;
                green <= 0;
                blue  <= 0;
            end
        end
    end

    assign clk = clock;
    assign sync = 1'b0;
    assign blank = hsync & vsync;

    assign next_x = (h_state == H_ACTIVE_STATE) ? h_counter : 10'd0;
    assign next_y = (v_state == V_ACTIVE_STATE) ? v_counter : 10'd0;

endmodule

